{
  "name": "The Clarity Engine",
  "description": "A precision analysis tool that evaluates public statements for structural completeness and accountability, utilizing the Gemini 3 Pro model for deep reasoning."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ElementStatus {
  CLEAR = 'CLEAR',
  BROAD = 'BROAD',
  MISSING = 'MISSING',
}

export interface AnalysisElement {
  content: string;
  status: ElementStatus;
  reasoning: string;
}

export interface StatementAnalysis {
  original_text: string;
  elements: {
    who: AnalysisElement;
    action: AnalysisElement;
    object: AnalysisElement;
    measure: AnalysisElement;
    when: AnalysisElement;
    premise: AnalysisElement;
  };
}

export interface FullAnalysisResponse {
  statement_analysis: StatementAnalysis;
  literal_translation: string;
}

export enum ClarityTier {
  TIER_1 = 'Tier 1 (Low Ambiguity)',
  TIER_2 = 'Tier 2 (Medium Ambiguity)',
  TIER_3 = 'Tier 3 (High Ambiguity)',
}

export interface CalculatedScore {
  rawPenaltyScore: number;
  finalAmbiguityScore: number;
  tier: ClarityTier;
  missingCount: number;
  criticalFailure: boolean; // True if Who and Action are both Missing
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

import { ElementStatus } from './types';

export const SYSTEM_PROMPT = `
Role: You are The Clarity Engine, a rigorous logic analyzer. 
Input: A string of text (political/corporate statement). 
Task: Deconstruct the text into 6 elements, assign states (CLEAR, BROAD, MISSING).
Constraint: Do not judge truth. Judge structural completeness.

THE CLARITY DOCTRINE (STRICT RULES):

1. The Binary Action Rule (The "Did it happen?" Test):
   - CLEAR: Binary Event (Sign, Resign, Vote, Veto). Can be answered Yes/No.
   - BROAD: Process with Endpoint (Review, Draft, Negotiate). Finite task, quality is subjective.
   - MISSING: Infinite Process / State of Being (Support, Fight, Believe, Prioritize, Ensure). No completion state.

2. The Premise Rule (Authoritative vs. Causal):
   - CLEAR: Points to External Reality (Data, Law, Specific Event).
   - BROAD: Points to Internal/Causal Logic ("To stimulate growth").
   - MISSING: Rhetorical/Circular ("Because it is right").

3. The Hierarchy of Missing Elements:
   - If WHO is Missing/Symbolic AND ACTION is Missing/Symbolic, it is a critical failure.

JSON Output Schema:
{
  "statement_analysis": {
    "original_text": "string",
    "elements": {
      "who": { "content": "string", "status": "CLEAR|BROAD|MISSING", "reasoning": "string" },
      "action": { "content": "string", "status": "CLEAR|BROAD|MISSING", "reasoning": "string" },
      "object": { "content": "string", "status": "CLEAR|BROAD|MISSING", "reasoning": "string" },
      "measure": { "content": "string", "status": "CLEAR|BROAD|MISSING", "reasoning": "string" },
      "when": { "content": "string", "status": "CLEAR|BROAD|MISSING", "reasoning": "string" },
      "premise": { "content": "string", "status": "CLEAR|BROAD|MISSING", "reasoning": "string" }
    }
  },
  "literal_translation": "string (The statement rewritten to include ONLY the clear commitments, stripping all rhetoric. If nothing is clear, say 'No structural commitments found.')"
}
`;

export const WEIGHTS = {
  who: 3.0,
  action: 2.0,
  object: 1.0,
  measure: 2.0,
  when: 1.5,
  premise: 2.5,
};

export const MAX_SCORE = 12.0;

export const STATUS_PENALTY_MULTIPLIER = {
  [ElementStatus.CLEAR]: 0,
  [ElementStatus.BROAD]: 0.5,
  [ElementStatus.MISSING]: 1.0,
};

export const TIER_THRESHOLDS = {
  TIER_1_LIMIT: 2.5,
  TIER_2_LIMIT: 6.0,
};

import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_PROMPT } from "../constants";
import { FullAnalysisResponse } from "../types";

// Helper to get API key safely
const getApiKey = (): string => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.error("API_KEY is not set in the environment.");
    return "";
  }
  return apiKey;
};

export const analyzeStatement = async (text: string): Promise<FullAnalysisResponse> => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API Key missing");

  const ai = new GoogleGenAI({ apiKey });

  // Using gemini-3-pro-preview for deep reasoning as requested ("Think more when needed")
  // and strictly enforcing JSON schema.
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: text,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        thinkingConfig: { thinkingBudget: 32768 }, // Max thinking for pro
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            statement_analysis: {
              type: Type.OBJECT,
              properties: {
                original_text: { type: Type.STRING },
                elements: {
                  type: Type.OBJECT,
                  properties: {
                    who: {
                      type: Type.OBJECT,
                      properties: {
                        content: { type: Type.STRING },
                        status: { type: Type.STRING, enum: ["CLEAR", "BROAD", "MISSING"] },
                        reasoning: { type: Type.STRING }
                      },
                      required: ["content", "status", "reasoning"]
                    },
                    action: {
                      type: Type.OBJECT,
                      properties: {
                        content: { type: Type.STRING },
                        status: { type: Type.STRING, enum: ["CLEAR", "BROAD", "MISSING"] },
                        reasoning: { type: Type.STRING }
                      },
                      required: ["content", "status", "reasoning"]
                    },
                    object: {
                      type: Type.OBJECT,
                      properties: {
                        content: { type: Type.STRING },
                        status: { type: Type.STRING, enum: ["CLEAR", "BROAD", "MISSING"] },
                        reasoning: { type: Type.STRING }
                      },
                      required: ["content", "status", "reasoning"]
                    },
                    measure: {
                      type: Type.OBJECT,
                      properties: {
                        content: { type: Type.STRING },
                        status: { type: Type.STRING, enum: ["CLEAR", "BROAD", "MISSING"] },
                        reasoning: { type: Type.STRING }
                      },
                      required: ["content", "status", "reasoning"]
                    },
                    when: {
                      type: Type.OBJECT,
                      properties: {
                        content: { type: Type.STRING },
                        status: { type: Type.STRING, enum: ["CLEAR", "BROAD", "MISSING"] },
                        reasoning: { type: Type.STRING }
                      },
                      required: ["content", "status", "reasoning"]
                    },
                    premise: {
                      type: Type.OBJECT,
                      properties: {
                        content: { type: Type.STRING },
                        status: { type: Type.STRING, enum: ["CLEAR", "BROAD", "MISSING"] },
                        reasoning: { type: Type.STRING }
                      },
                      required: ["content", "status", "reasoning"]
                    }
                  },
                  required: ["who", "action", "object", "measure", "when", "premise"]
                }
              },
              required: ["original_text", "elements"]
            },
            literal_translation: { type: Type.STRING }
          },
          required: ["statement_analysis", "literal_translation"]
        }
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as FullAnalysisResponse;
    } else {
      throw new Error("Empty response from Gemini");
    }
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

export const streamChat = async function* (history: { role: string; parts: { text: string }[] }[], newMessage: string) {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API Key missing");

  const ai = new GoogleGenAI({ apiKey });

  // Using gemini-2.5-flash-lite for fast, low-latency chat responses
  const chat = ai.chats.create({
    model: 'gemini-2.5-flash-lite',
    history: history,
    config: {
      systemInstruction: "You are the Clarity Engine Assistant. Help users understand the clarity analysis principles: WHO, ACTION, OBJECT, MEASURE, WHEN, PREMISE. Explain why specificity matters. Keep answers concise and helpful."
    }
  });

  const result = await chat.sendMessageStream({ message: newMessage });
  for await (const chunk of result) {
    yield chunk.text;
  }
};

import React from 'react';

