import React, { useState } from 'react';

interface InputSectionProps {
  onAnalyze: (text: string) => void;
  isLoading: boolean;
}

const InputSection: React.FC<InputSectionProps> = ({ onAnalyze, isLoading }) => {
  const [text, setText] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (text.trim()) {
      onAnalyze(text);
    }
  };

  return (
    <section className="bg-white border border-slate-200 shadow-sm rounded-none p-6 md:p-8 mb-8">
      <form onSubmit={handleSubmit}>
        <label htmlFor="statement" className="block text-xs font-bold font-mono text-slate-500 uppercase tracking-wider mb-3">
          Input Statement
        </label>
        <textarea
          id="statement"
          className="w-full h-40 p-4 font-mono text-sm bg-slate-50 border border-slate-300 focus:border-slate-900 focus:ring-0 transition-colors resize-none rounded-sm text-slate-900 placeholder:text-slate-400"
          placeholder="Paste headline, speech snippet, or press release here..."
          maxLength={500}
          value={text}
          onChange={(e) => setText(e.target.value)}
          disabled={isLoading}
        />
        <div className="flex justify-between items-center mt-4">
          <span className="text-xs font-mono text-slate-400">
            {text.length}/500 Characters
          </span>
          <button
            type="submit"
            disabled={isLoading || !text.trim()}
            className={`px-8 py-3 font-mono text-sm font-bold uppercase tracking-wide text-white transition-all 
              ${isLoading || !text.trim() ? 'bg-slate-300 cursor-not-allowed' : 'bg-slate-900 hover:bg-slate-800'}`}
          >
            {isLoading ? 'Atomizing...' : 'Analyze'}
          </button>
        </div>
      </form>
    </section>
  );
};

export default InputSection;

import React from 'react';
import { AnalysisElement, CalculatedScore, ElementStatus, FullAnalysisResponse, ClarityTier } from '../types';

interface ClarityCardProps {
  analysis: FullAnalysisResponse;
  score: CalculatedScore;
}

const getElementColorClass = (status: ElementStatus) => {
  switch (status) {
    case ElementStatus.CLEAR:
      return 'border-emerald-500 bg-emerald-50/50 text-emerald-900';
    case ElementStatus.BROAD:
      return 'border-amber-500 bg-amber-50/50 text-amber-900';
    case ElementStatus.MISSING:
      return 'border-rose-500 border-dashed bg-rose-50/50 text-rose-900';
    default:
      return 'border-slate-200';
  }
};

const getStatusBadgeClass = (status: ElementStatus) => {
  switch (status) {
    case ElementStatus.CLEAR:
      return 'bg-emerald-100 text-emerald-700';
    case ElementStatus.BROAD:
      return 'bg-amber-100 text-amber-700';
    case ElementStatus.MISSING:
      return 'bg-rose-100 text-rose-700';
    default:
      return 'bg-slate-100 text-slate-500';
  }
};

const ElementBox: React.FC<{ title: string; element: AnalysisElement; weight: number }> = ({ title, element, weight }) => {
  return (
    <div className={`p-4 border-l-4 ${getElementColorClass(element.status)} bg-white shadow-sm`}>
      <div className="flex justify-between items-start mb-2">
        <h4 className="text-xs font-bold font-mono uppercase opacity-70 tracking-wider">{title}</h4>
        <span className={`text-[10px] font-mono font-bold px-2 py-0.5 rounded uppercase ${getStatusBadgeClass(element.status)}`}>
          {element.status}
        </span>
      </div>
      <p className={`font-sans text-sm mb-2 ${element.status === ElementStatus.CLEAR ? 'font-semibold' : 'font-normal'}`}>
        {element.content || "N/A"}
      </p>
      <p className="text-xs font-mono text-slate-500 leading-relaxed border-t border-slate-100 pt-2 mt-2">
        {element.reasoning}
      </p>
      <div className="mt-2 text-[10px] text-slate-400 font-mono text-right">
        Max Weight: {weight} pts
      </div>
    </div>
  );
};

const ClarityCard: React.FC<ClarityCardProps> = ({ analysis, score }) => {
  const { statement_analysis } = analysis;
  const elements = statement_analysis.elements;

  const scoreColor = 
    score.tier === ClarityTier.TIER_1 ? 'text-emerald-600' :
    score.tier === ClarityTier.TIER_2 ? 'text-amber-500' :
    'text-rose-600';

  return (
    <div className="animate-fade-in">
      {/* Header Result */}
      <div className="bg-white border border-slate-200 shadow-sm p-6 mb-6 flex flex-col md:flex-row items-center justify-between">
        <div className="mb-4 md:mb-0">
          <h2 className="text-sm font-mono text-slate-500 uppercase tracking-widest mb-1">Ambiguity Score</h2>
          <div className={`text-6xl font-bold font-mono tracking-tighter ${scoreColor}`}>
            {score.finalAmbiguityScore.toFixed(1)}
          </div>
        </div>
        <div className="text-center md:text-right">
          <div className={`text-lg font-bold font-mono uppercase px-4 py-2 border-2 inline-block mb-2
             ${score.tier === ClarityTier.TIER_1 ? 'border-emerald-500 text-emerald-700 bg-emerald-50' : 
               score.tier === ClarityTier.TIER_2 ? 'border-amber-500 text-amber-700 bg-amber-50' : 
               'border-rose-500 text-rose-700 bg-rose-50'}`}>
            {score.tier}
          </div>
          <p className="text-xs text-slate-400 font-mono">
            {score.criticalFailure ? 'CRITICAL FAILURE: Agent & Action Missing' : 
             score.missingCount >= 3 ? '3 STRIKES RULE APPLIED' : 'Standard Calculation'}
          </p>
        </div>
      </div>

      {/* Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 mb-6">
        <ElementBox title="1. Who (Agent)" element={elements.who} weight={3.0} />
        <ElementBox title="2. Action (Verb)" element={elements.action} weight={2.0} />
        <ElementBox title="3. Object (Target)" element={elements.object} weight={1.0} />
        <ElementBox title="4. Measure (Metric)" element={elements.measure} weight={2.0} />
        <ElementBox title="5. When (Timeline)" element={elements.when} weight={1.5} />
        <ElementBox title="6. Premise (Why)" element={elements.premise} weight={2.5} />
      </div>

      {/* Translation */}
      <div className="bg-slate-900 text-slate-100 p-6 shadow-sm border-l-4 border-slate-500">
        <h3 className="text-xs font-bold font-mono text-slate-400 uppercase tracking-widest mb-3">
          Literal Interpretation
        </h3>
        <p className="font-mono text-sm leading-relaxed">
          {analysis.literal_translation}
        </p>
      </div>
    </div>
  );
};

export default ClarityCard;

import React, { useState, useRef, useEffect } from 'react';
import { streamChat } from '../services/geminiService';
import { ChatMessage } from '../types';

const ChatWidget: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: 'Hello. I am the Clarity Assistant. Ask me about ambiguity scoring or specific rules.' }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isOpen]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    const userMsg: ChatMessage = { role: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    try {
      // Format history for Gemini API
      const history = messages.map(m => ({
        role: m.role,
        parts: [{ text: m.text }]
      }));

      let fullResponse = "";
      const stream = streamChat(history, userMsg.text);

      // Add placeholder for model response
      setMessages(prev => [...prev, { role: 'model', text: '' }]);

      for await (const chunk of stream) {
        if (chunk) {
          fullResponse += chunk;
          setMessages(prev => {
             const newMsgs = [...prev];
             newMsgs[newMsgs.length - 1].text = fullResponse;
             return newMsgs;
          });
        }
      }
    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { role: 'model', text: "Error: Could not connect to Clarity Assistant." }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="mb-4 w-80 md:w-96 h-96 bg-white border border-slate-200 shadow-xl flex flex-col animate-fade-in-up">
          <div className="bg-slate-900 text-white p-3 flex justify-between items-center">
            <h3 className="text-xs font-mono font-bold uppercase tracking-wider">Clarity Assistant</h3>
            <button onClick={() => setIsOpen(false)} className="text-slate-400 hover:text-white">&times;</button>
          </div>
          <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50">
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-3 text-xs font-sans rounded-sm border ${
                  msg.role === 'user' 
                    ? 'bg-white border-slate-300 text-slate-900' 
                    : 'bg-slate-200 border-slate-300 text-slate-800'
                }`}>
                  {msg.text}
                </div>
              </div>
            ))}
            {isTyping && <div className="text-xs font-mono text-slate-400 ml-2">Thinking...</div>}
            <div ref={messagesEndRef} />
          </div>
          <form onSubmit={handleSend} className="p-3 bg-white border-t border-slate-200">
            <div className="flex">
              <input
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                placeholder="Ask a question..."
                className="flex-1 text-xs font-mono border border-slate-300 p-2 focus:outline-none focus:border-slate-900"
              />
              <button 
                type="submit" 
                className="ml-2 bg-slate-900 text-white px-3 py-1 text-xs font-bold uppercase hover:bg-slate-800"
                disabled={isTyping}
              >
                Send
              </button>
            </div>
          </form>
        </div>
      )}

      <button
        onClick={() => setIsOpen(!isOpen)}
        className="h-12 w-12 rounded-full bg-slate-900 text-white shadow-lg flex items-center justify-center hover:bg-slate-800 transition-all hover:scale-105"
      >
        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
           {isOpen ? (
             <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
           ) : (
             <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />
           )}
        </svg>
      </button>
    </div>
  );
};

export default ChatWidget;

import React, { useState } from 'react';
import Header from './components/Header';
import InputSection from './components/InputSection';
import ClarityCard from './components/ClarityCard';
import ChatWidget from './components/ChatWidget';
import { analyzeStatement } from './services/geminiService';
import { 
  FullAnalysisResponse, 
  CalculatedScore, 
  ElementStatus, 
  ClarityTier,
  StatementAnalysis 
} from './types';
import { WEIGHTS, STATUS_PENALTY_MULTIPLIER, MAX_SCORE, TIER_THRESHOLDS } from './constants';

const App: React.FC = () => {
  const [analysis, setAnalysis] = useState<FullAnalysisResponse | null>(null);
  const [score, setScore] = useState<CalculatedScore | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const calculateScore = (analysisData: StatementAnalysis): CalculatedScore => {
    const els = analysisData.elements;
    let rawPenaltyScore = 0;
    let missingCount = 0;

    // Helper to calc element score
    const calcElement = (status: ElementStatus, weight: number) => {
      const penalty = STATUS_PENALTY_MULTIPLIER[status];
      if (status === ElementStatus.MISSING) missingCount++;
      return weight * penalty;
    };

    rawPenaltyScore += calcElement(els.who.status as ElementStatus, WEIGHTS.who);
    rawPenaltyScore += calcElement(els.action.status as ElementStatus, WEIGHTS.action);
    rawPenaltyScore += calcElement(els.object.status as ElementStatus, WEIGHTS.object);
    rawPenaltyScore += calcElement(els.measure.status as ElementStatus, WEIGHTS.measure);
    rawPenaltyScore += calcElement(els.when.status as ElementStatus, WEIGHTS.when);
    rawPenaltyScore += calcElement(els.premise.status as ElementStatus, WEIGHTS.premise);

    let finalAmbiguityScore = (rawPenaltyScore / MAX_SCORE) * 10;

    // Rule D: Hierarchy of Missing Elements
    // If WHO and ACTION are both MISSING, Score is 10.0
    const criticalFailure = els.who.status === ElementStatus.MISSING && els.action.status === ElementStatus.MISSING;
    if (criticalFailure) {
      finalAmbiguityScore = 10.0;
    }

    let tier = ClarityTier.TIER_1;
    if (finalAmbiguityScore > TIER_THRESHOLDS.TIER_2_LIMIT) {
      tier = ClarityTier.TIER_3;
    } else if (finalAmbiguityScore > TIER_THRESHOLDS.TIER_1_LIMIT) {
      tier = ClarityTier.TIER_2;
    }

    // Rule C: The Tier Floor Rule (3 Strikes)
    // If >= 3 elements are MISSING, auto Tier 3
    if (missingCount >= 3) {
      tier = ClarityTier.TIER_3;
    }

    return {
      rawPenaltyScore,
      finalAmbiguityScore,
      tier,
      missingCount,
      criticalFailure
    };
  };

  const handleAnalyze = async (text: string) => {
    setIsLoading(true);
    setError(null);
    setAnalysis(null);
    setScore(null);

    try {
      const result = await analyzeStatement(text);
      setAnalysis(result);
      const computedScore = calculateScore(result.statement_analysis);
      setScore(computedScore);
    } catch (err) {
      console.error(err);
      setError("Analysis failed. Please try again. Ensure your API Key is valid.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      <Header />

      <main className="flex-1 container mx-auto px-4 max-w-4xl py-8">

        <InputSection onAnalyze={handleAnalyze} isLoading={isLoading} />

        {error && (
           <div className="bg-rose-100 border-l-4 border-rose-500 text-rose-700 p-4 mb-8 font-mono text-sm" role="alert">
             <p className="font-bold">Error</p>
             <p>{error}</p>
           </div>
        )}

        {isLoading && (
          <div className="flex flex-col items-center justify-center py-12 space-y-4 animate-pulse">
            <div className="w-16 h-16 border-4 border-slate-200 border-t-slate-800 rounded-full animate-spin"></div>
            <p className="font-mono text-slate-500 text-sm uppercase tracking-widest">Evaluating Commitments...</p>
          </div>
        )}

        {analysis && score && (
          <ClarityCard analysis={analysis} score={score} />
        )}

        {!analysis && !isLoading && !error && (
           <div className="text-center py-12 text-slate-400">
             <p className="font-mono text-xs uppercase tracking-widest mb-2">Clarity Engine Ready</p>
             <p className="font-sans text-sm">Paste a statement above to begin forensic analysis.</p>
           </div>
        )}
      </main>

      <footer className="bg-slate-900 text-slate-400 py-6 mt-12 border-t border-slate-800">
        <div className="container mx-auto px-4 max-w-4xl text-center">
          <p className="font-mono text-xs uppercase tracking-widest">
            Powered by Gemini 3 Pro • Deep Reasoning Logic
          </p>
        </div>
      </footer>

      <ChatWidget />
    </div>
  );
};

