};

const ClarityCard: React.FC<ClarityCardProps> = ({ analysis, score }) => {
  const [showLogic, setShowLogic] = useState(false);
  const [stressTestMode, setStressTestMode] = useState(false);
  const { statement_analysis } = analysis;
  const elements = statement_analysis.elements;

  const clearCount = (Object.values(elements) as AnalysisElement[]).filter(e => e.status === ElementStatus.CLEAR).length;
  const densityPercent = Math.round((clearCount / 6) * 100);

  // Parse atomic commitments
  const atomicCommitments = analysis.literal_translation.split(' || ').map(s => s.trim());

  return (
    <div className="animate-fade-in space-y-6">

      {/* Top Card: Score & Density */}
      <div className="bg-white border border-slate-200 shadow-sm p-6 relative overflow-hidden">
        <div className="flex flex-col md:flex-row justify-between items-center gap-6">

          {/* Left: Score Gauge */}
          <div className="flex flex-col items-center">
             <ScoreGauge score={score} density={densityPercent} />
             <div className={`mt-4 px-3 py-1 text-xs font-bold uppercase rounded-full border
                ${score.tier === ClarityTier.TIER_1 ? 'border-emerald-200 text-emerald-700 bg-emerald-50' : 
                  score.tier === ClarityTier.TIER_2 ? 'border-amber-200 text-amber-700 bg-amber-50' : 
                  'border-rose-200 text-rose-700 bg-rose-50'}`}>
               {score.tier}
             </div>
          </div>

          {/* Center: Commitment Density */}
          <div className="flex-1 w-full">
            <div className="flex justify-between items-end mb-2">
              <h3 className="text-xs font-mono font-bold uppercase text-slate-500 tracking-wider">Commitment Density</h3>
              <span className="text-sm font-mono font-bold text-slate-900">{clearCount}/6 Elements Clear</span>
            </div>
            <div className="h-4 bg-slate-100 rounded-sm overflow-hidden flex">
              {[...Array(6)].map((_, i) => (
                <div key={i} className={`flex-1 border-r border-white last:border-0 transition-colors duration-500
                  ${i < clearCount ? 'bg-slate-800' : 'bg-slate-200'}`} 
                />
              ))}
            </div>
            <p className="mt-2 text-xs text-slate-400 font-mono">
              {clearCount < 3 ? "Low structural integrity. Highly susceptible to drift." : "Moderate to high structural definition."}
            </p>
          </div>

          {/* Right: Ambiguity Sources Breakdown */}
          <div className="w-full md:w-1/3">
             <h3 className="text-xs font-mono font-bold uppercase text-slate-500 tracking-wider mb-2">Ambiguity Source</h3>
             <div className="space-y-1">
               {(Object.entries(elements) as [string, AnalysisElement][]).map(([key, el]) => {
                  if (el.status === ElementStatus.CLEAR) return null;
                  const weight = WEIGHTS[key as keyof typeof WEIGHTS];
                  const penalty = el.status === ElementStatus.MISSING ? 1 : 0.5;
                  const contribution = (weight * penalty) / 12 * 100;
                  return (
                    <div key={key} className="flex items-center text-[10px] font-mono">
                      <span className="w-12 uppercase text-slate-400">{key}</span>
                      <div className="flex-1 h-1.5 bg-slate-100 rounded-sm mx-2 overflow-hidden">
                        <div className="h-full bg-rose-400" style={{ width: `${contribution * 3}%` }}></div>
                      </div>
                      <span className="text-rose-500">{el.status}</span>
                    </div>
                  )
               })}
               {clearCount === 6 && <div className="text-[10px] text-emerald-500 font-mono">No ambiguity sources detected.</div>}
             </div>
          </div>

        </div>

        {/* Logic Toggle */}
        <div className="mt-6 pt-4 border-t border-slate-100 flex justify-between items-center">
           <button 
            onClick={() => setShowLogic(!showLogic)}
            className="text-[10px] font-mono font-bold text-slate-400 hover:text-slate-600 uppercase tracking-wide"
          >
            {showLogic ? 'Hide Formula' : 'Show Calculation Logic'}
          </button>

          <div className="flex items-center gap-2">
            <span className="text-[10px] font-mono text-slate-400 uppercase tracking-wide">Stress Test Mode</span>
            <button 
              onClick={() => setStressTestMode(!stressTestMode)}
              className={`w-8 h-4 rounded-full p-0.5 transition-colors ${stressTestMode ? 'bg-rose-500' : 'bg-slate-300'}`}
            >
              <div className={`w-3 h-3 bg-white rounded-full shadow-sm transition-transform ${stressTestMode ? 'translate-x-4' : 'translate-x-0'}`} />
            </button>
          </div>
        </div>

        {showLogic && (
             <div className="mt-4 bg-slate-50 p-4 rounded-sm border border-slate-200 text-xs font-mono text-slate-600">
               <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                 <div>
                   <strong className="block text-slate-900 mb-1">WEIGHTS:</strong>
                   <ul className="list-disc pl-4 space-y-1">
                     <li>WHO (3.0), ACTION (2.0), PREMISE (2.5)</li>
                     <li>MEASURE (2.0), WHEN (1.5), OBJECT (1.0)</li>
                   </ul>
                 </div>
                 <div>
                   <strong className="block text-slate-900 mb-1">PENALTIES:</strong>
                   <ul className="list-disc pl-4 space-y-1">
                     <li>CLEAR: 0% | BROAD: 50% | MISSING: 100%</li>
                     <li>Critical Failure: Who & Action Missing = Score 10</li>
                   </ul>
                 </div>
               </div>
            </div>
        )}
      </div>

      {/* Main Grid */}
      <div className={`grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 transition-opacity duration-500 ${stressTestMode ? 'opacity-90' : 'opacity-100'}`}>
        <ElementBox id="who" title="1. Who (Agent)" element={elements.who} weight={3.0} isStressTest={stressTestMode} />
        <ElementBox id="action" title="2. Action (Verb)" element={elements.action} weight={2.0} isStressTest={stressTestMode} />
        <ElementBox id="object" title="3. Object (Target)" element={elements.object} weight={1.0} isStressTest={stressTestMode} />
        <ElementBox id="measure" title="4. Measure (Metric)" element={elements.measure} weight={2.0} isStressTest={stressTestMode} />
        <ElementBox id="when" title="5. When (Timeline)" element={elements.when} weight={1.5} isStressTest={stressTestMode} />
        <ElementBox id="premise" title="6. Premise (Why)" element={elements.premise} weight={2.5} isStressTest={stressTestMode} />
      </div>

       {/* Stress Test Warning */}
       {stressTestMode && (
         <div className="bg-rose-900 text-white p-4 border-l-4 border-rose-500 animate-fade-in">
            <h4 className="text-xs font-bold font-mono uppercase tracking-widest mb-1 text-rose-300">Stress Test Analysis (Time Decay)</h4>
            <p className="font-mono text-sm">
               Projecting 6 months forward: All "BROAD" or "MISSING" elements have degraded to unverifiable noise. 
               {clearCount < 3 ? " The statement has effectively dissolved." : " Only the highlighted elements remain binding."}
            </p>
         </div>
       )}

      {/* Atomic Commitments / Translation */}
      <div className="bg-slate-900 text-slate-100 p-6 shadow-sm border-l-4 border-slate-500">
        <h3 className="text-xs font-bold font-mono text-slate-400 uppercase tracking-widest mb-3">
          Atomic Commitments (Literal Reality)
        </h3>
        {atomicCommitments.length > 1 ? (
          <ul className="list-disc pl-5 space-y-2">
            {atomicCommitments.map((commit, idx) => (
              <li key={idx} className="font-mono text-sm leading-relaxed">{commit}</li>
            ))}
          </ul>
        ) : (
          <p className="font-mono text-sm leading-relaxed">
            {analysis.literal_translation}
          </p>
        )}
      </div>
    </div>
  );
};

