             <div className="bg-rose-900 text-white p-4 rounded-lg border-l-4 border-rose-500 shadow-md">
                <h4 className="text-xs font-bold font-mono uppercase tracking-widest mb-1 text-rose-300">Stress Test Analysis</h4>
                <p className="font-mono text-sm">
                   Projecting forward: All items dimmed above are likely to be reinterpreted, ignored, or forgotten because they lack structural binding.
                </p>
             </div>
           )}

           {/* Ambiguity Source Bar */}
           {!stressTestMode && (
             <div className="bg-white p-4 rounded-lg border border-slate-200 shadow-sm">
                 <h4 className="text-xs font-bold font-mono uppercase text-slate-500 mb-3">Ambiguity Sources</h4>
                 <div className="space-y-2">
                   {(Object.entries(elements) as [string, AnalysisElement][]).map(([key, el]) => {
                      if (el.status === ElementStatus.CLEAR) return null;
                      const weight = WEIGHTS[key as keyof typeof WEIGHTS];
                      const penalty = el.status === ElementStatus.MISSING ? 1 : 0.5;
                      const contribution = (weight * penalty) / 12 * 100;
                      return (
                        <div key={key} className="flex items-center text-[10px] font-mono">
                          <span className="w-16 uppercase text-slate-400 font-bold">{key}</span>
                          <div className="flex-1 h-2 bg-slate-100 rounded-sm mx-2 overflow-hidden">
                            <div className="h-full bg-rose-400" style={{ width: `${contribution * 3}%` }}></div>
                          </div>
                          <span className="text-rose-500 font-bold">{el.status}</span>
                        </div>
                      )
                   })}
                   {clearCount === 6 && <div className="text-xs text-emerald-600 font-mono">No ambiguity sources detected. Solid structure.</div>}
                 </div>
             </div>
           )}

        </div>
      )}

    </div>
  );
};

