          <div className="mb-8 opacity-0 animate-fade-in-up-delay-1" style={{ animationFillMode: 'forwards' }}>
             <div className="flex justify-between text-xs font-mono font-bold uppercase text-slate-500 mb-2">
               <span>Commitment Density</span>
               <span>{clearCount}/6 Anchors</span>
             </div>
             <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden flex gap-0.5">
               {[...Array(6)].map((_, i) => (
                 <div key={i} className={`flex-1 rounded-sm transition-all duration-1000 ease-out
                   ${i < clearCount ? 'bg-slate-800' : 'bg-slate-200'}`} 
