            type="submit"
            disabled={isLoading || !text.trim()}
            className={`px-8 py-3 font-mono text-sm font-bold uppercase tracking-wide text-white transition-all 
              ${isLoading || !text.trim() ? 'bg-slate-300 dark:bg-slate-700 cursor-not-allowed' : 'bg-slate-900 dark:bg-slate-700 hover:bg-slate-800 dark:hover:bg-slate-600'}`}
          >
            {isLoading ? 'Atomizing...' : 'Analyze'}
          </button>
        </div>
      </form>
    </section>
  );
};

export default InputSection;

import React, { useState, useEffect, useRef } from 'react';
import { AnalysisElement, CalculatedScore, ElementStatus, FullAnalysisResponse, ClarityTier } from '../types';
import { ELEMENT_DEFINITIONS, WEIGHTS, HUMAN_LABELS } from '../constants';

interface ClarityCardProps {
  analysis: FullAnalysisResponse;
  score: CalculatedScore;
}

// --- Icons ---
const StatusIcon: React.FC<{ status: ElementStatus; className?: string }> = ({ status, className }) => {
  switch (status) {
    case ElementStatus.CLEAR:
      return (
        <svg xmlns="http://www.w3.org/2000/svg" className={`h-5 w-5 text-emerald-600 dark:text-emerald-500 ${className}`} viewBox="0 0 20 20" fill="currentColor">
          <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
        </svg>
      );
    case ElementStatus.BROAD:
      return (
        <svg xmlns="http://www.w3.org/2000/svg" className={`h-5 w-5 text-amber-500 ${className}`} viewBox="0 0 20 20" fill="currentColor">
          <path fillRule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
        </svg>
      );
    case ElementStatus.MISSING:
      return (
        <svg xmlns="http://www.w3.org/2000/svg" className={`h-5 w-5 text-rose-500 ${className}`} viewBox="0 0 20 20" fill="currentColor">
          <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd" />
        </svg>
      );
    default:
      return null;
  }
};

const ChevronDown: React.FC<{ className?: string }> = ({ className }) => (
  <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
    <path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" />
  </svg>
);

// --- Components ---

const StickyPill: React.FC<{ score: CalculatedScore }> = ({ score }) => {
  return (
    <div className="sticky top-4 z-40 flex justify-center pointer-events-none animate-fade-in-up">
      <div className="bg-slate-900/95 dark:bg-slate-800/95 backdrop-blur-md text-white px-4 py-2 rounded-full shadow-lg flex items-center gap-3 border border-slate-700 pointer-events-auto transition-transform hover:scale-105">
        <span className={`text-xs font-bold font-mono uppercase px-1.5 py-0.5 rounded text-slate-900 
          ${score.tier === ClarityTier.TIER_1 ? 'bg-emerald-400' : 
            score.tier === ClarityTier.TIER_2 ? 'bg-amber-400' : 
            'bg-rose-400'}`}>
          {score.tier.split(' ')[0]} {score.tier.split(' ')[1]}
        </span>
        <span className="font-mono font-bold text-sm">{score.finalAmbiguityScore.toFixed(1)}</span>
      </div>
    </div>
  );
};

const ChecklistItem: React.FC<{ 
  id: string; 
  title: string; 
  element: AnalysisElement; 
  isStressTest: boolean 
}> = ({ id, title, element, isStressTest }) => {
  const [isOpen, setIsOpen] = useState(false);
  const isDimmed = isStressTest && element.status !== ElementStatus.CLEAR;

  // Auto-expand if missing or broad in normal mode to show reasoning
  useEffect(() => {
    if (!isStressTest && element.status !== ElementStatus.CLEAR) {
      // Optional: default to open for non-clear items? 
      // Keeping closed by default for "glanceability", user taps to see why.
    }
  }, [isStressTest, element.status]);

  return (
    <div 
      className={`border-b border-slate-100 dark:border-slate-700 last:border-0 transition-all duration-300 
        ${isDimmed ? 'opacity-30 grayscale' : 'opacity-100'}
        ${isOpen ? 'bg-slate-50 dark:bg-slate-800/50' : 'hover:bg-slate-50 dark:hover:bg-slate-800/30'}`}
    >
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="w-full flex items-center p-4 text-left focus:outline-none group"
      >
        <div className="mr-3 mt-0.5">
          <StatusIcon status={element.status} />
        </div>
        <div className="flex-1">
          <div className="flex justify-between items-center">
            <h4 className="text-sm font-medium font-sans text-slate-900 dark:text-slate-200 group-hover:text-slate-700 dark:group-hover:text-white transition-colors">
              {title}
            </h4>
            <div className="flex items-center gap-2">
              <span className={`text-[10px] font-mono font-bold uppercase px-2 py-0.5 rounded-sm
                ${element.status === ElementStatus.CLEAR ? 'bg-emerald-100/50 dark:bg-emerald-900/30 text-emerald-800 dark:text-emerald-400' :
                  element.status === ElementStatus.BROAD ? 'bg-amber-100/50 dark:bg-amber-900/30 text-amber-800 dark:text-amber-400' :
                  'bg-rose-100/50 dark:bg-rose-900/30 text-rose-800 dark:text-rose-400'}`}>
                {element.status}
              </span>
              <ChevronDown className={`h-4 w-4 text-slate-400 transition-transform duration-300 ${isOpen ? 'rotate-180' : ''}`} />
            </div>
          </div>
          {!isOpen && (
            <p className="text-xs text-slate-500 dark:text-slate-400 font-sans mt-1 truncate pr-4">
              {element.content || "Not specified"}
            </p>
          )}
        </div>
      </button>

      {/* Accordion Content */}
      <div className={`overflow-hidden transition-all duration-300 ease-in-out ${isOpen ? 'max-h-48 opacity-100' : 'max-h-0 opacity-0'}`}>
        <div className="px-4 pb-4 pl-12">
          <p className="text-sm text-slate-800 dark:text-slate-200 font-sans font-medium mb-2 leading-relaxed">
            "{element.content || "N/A"}"
          </p>
          <div className="p-3 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-lg shadow-sm">
            <div className="flex items-start gap-2">
               <span className="text-[10px] font-mono uppercase text-slate-400 mt-0.5">Rule:</span>
               <p className="text-xs text-slate-600 dark:text-slate-300 font-sans leading-relaxed">
                 {ELEMENT_DEFINITIONS[id as keyof typeof ELEMENT_DEFINITIONS]}
               </p>
            </div>
            <div className="flex items-start gap-2 mt-2 pt-2 border-t border-slate-100 dark:border-slate-800">
               <span className="text-[10px] font-mono uppercase text-slate-400 mt-0.5">Analysis:</span>
               <p className="text-xs text-slate-600 dark:text-slate-300 font-mono leading-relaxed">
                 {isDimmed ? "This element relies on interpretation and will likely degrade over time." : element.reasoning}
               </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const ClarityCard: React.FC<ClarityCardProps> = ({ analysis, score }) => {
  const [showDeepDive, setShowDeepDive] = useState(false);
  const [showHighlight, setShowHighlight] = useState(false);
  const [stressTestMode, setStressTestMode] = useState(false);
  const [showAssumptions, setShowAssumptions] = useState(false);
  const [showSticky, setShowSticky] = useState(false);
  const verdictRef = useRef<HTMLDivElement>(null);

  const { statement_analysis } = analysis;
  const elements = statement_analysis.elements;
  const clearCount = (Object.values(elements) as AnalysisElement[]).filter(e => e.status === ElementStatus.CLEAR).length;
  const assumptions = statement_analysis.assumptions_to_avoid || [];

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        setShowSticky(!entry.isIntersecting);
      },
      { threshold: 0.2 }
    );

    if (verdictRef.current) {
      observer.observe(verdictRef.current);
    }

    return () => {
      if (verdictRef.current) observer.unobserve(verdictRef.current);
    };
  }, []);

  const handleShare = () => {
    if (navigator.share) {
      navigator.share({
        title: 'Clarity Analysis',
        text: `Verdict: ${score.tier} (${score.finalAmbiguityScore}/10). ${analysis.literal_translation}`,
      }).catch(console.error);
    } else {
      // Basic copy fallback
      navigator.clipboard.writeText(`Verdict: ${score.tier}. ${analysis.literal_translation}`);
      alert("Summary copied to clipboard.");
    }
  };

  const renderHighlightedText = (text: string) => {
    const parts = text.split(/(\*\*.*?\*\*)/g);
    return parts.map((part, i) => {
      if (part.startsWith('**') && part.endsWith('**')) {
        return <span key={i} className="bg-emerald-100/80 dark:bg-emerald-900/60 text-emerald-900 dark:text-emerald-300 font-semibold px-1 py-0.5 rounded-sm box-decoration-clone">{part.slice(2, -2)}</span>;
      }
      return <span key={i} className="text-slate-400 dark:text-slate-500 transition-opacity duration-500">{part}</span>;
    });
  };

  return (
    <div className="space-y-6 relative pb-24">

      {/* Sticky Context Pill - Appears when scrolling past verdict */}
      {showSticky && <StickyPill score={score} />}

      {/* 1. VERDICT CARD (Hero) */}
      <div ref={verdictRef} className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 shadow-sm rounded-xl overflow-hidden animate-fade-in-up transition-colors duration-300">
        {/* Header */}
        <div className="bg-slate-50/50 dark:bg-slate-800/50 px-6 py-5 border-b border-slate-100 dark:border-slate-800 flex justify-between items-start">
          <div>
            <span className="block text-[10px] font-mono uppercase tracking-widest text-slate-400 mb-1">Verdict</span>
            <div className={`text-xl md:text-2xl font-bold font-mono uppercase flex items-center gap-2 tracking-tight
              ${score.tier === ClarityTier.TIER_1 ? 'text-emerald-700 dark:text-emerald-400' : 
                score.tier === ClarityTier.TIER_2 ? 'text-amber-600 dark:text-amber-400' : 
                'text-rose-600 dark:text-rose-400'}`}>
               {score.tier === ClarityTier.TIER_1 ? <StatusIcon status={ElementStatus.CLEAR} className="h-6 w-6" /> : 
                score.tier === ClarityTier.TIER_2 ? <StatusIcon status={ElementStatus.BROAD} className="h-6 w-6" /> : 
                <StatusIcon status={ElementStatus.MISSING} className="h-6 w-6" />}
               {score.tier}
            </div>
          </div>
          <div className="text-right">
             <div className="text-4xl font-bold font-mono text-slate-900 dark:text-white tracking-tighter">{score.finalAmbiguityScore.toFixed(1)}</div>
             <div className="text-[10px] font-mono uppercase text-slate-400 mt-1">Ambiguity Score</div>
          </div>
        </div>

        {/* Content Body */}
        <div className="p-6 md:p-8">
          {/* Commitment Density Meter */}
          <div className="mb-8 opacity-0 animate-fade-in-up-delay-1" style={{ animationFillMode: 'forwards' }}>
             <div className="flex justify-between text-xs font-mono font-bold uppercase text-slate-500 dark:text-slate-400 mb-2">
               <span>Commitment Density</span>
               <span>{clearCount}/6 Anchors</span>
             </div>
             <div className="h-2 w-full bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden flex gap-0.5">
               {[...Array(6)].map((_, i) => (
                 <div key={i} className={`flex-1 rounded-sm transition-all duration-1000 ease-out
                   ${i < clearCount ? 'bg-slate-800 dark:bg-slate-400' : 'bg-slate-200 dark:bg-slate-700'}`} 
                 />
               ))}
             </div>
          </div>

          {/* Core Reality */}
          <div className="space-y-6 opacity-0 animate-fade-in-up-delay-2" style={{ animationFillMode: 'forwards' }}>
             <div>
               <h3 className="text-xs font-bold font-mono uppercase text-slate-400 mb-3 tracking-wider">Commitment Summary</h3>
               <div className="bg-emerald-50/50 dark:bg-emerald-900/20 border-l-4 border-emerald-500 dark:border-emerald-700 p-5 rounded-r-lg">
                 <p className="font-sans text-base text-slate-800 dark:text-slate-200 font-medium leading-relaxed">
                   "{analysis.literal_translation}"
                 </p>
               </div>
             </div>

             {statement_analysis.debate_reason && (
               <div>
                 <h3 className="text-xs font-bold font-mono uppercase text-slate-400 mb-2 tracking-wider">Debate Source</h3>
                 <p className="text-sm font-sans text-slate-600 dark:text-slate-300 border-l-4 border-amber-300 dark:border-amber-600 pl-4 py-1 leading-relaxed">
                   {statement_analysis.debate_reason}
                 </p>
               </div>
             )}
          </div>

          {/* Primary Actions */}
          <div className="mt-10 flex flex-col md:flex-row gap-3 opacity-0 animate-fade-in-up-delay-2" style={{ animationFillMode: 'forwards' }}>
             <button 
               onClick={() => setShowDeepDive(!showDeepDive)}
               className="flex-1 group bg-slate-900 hover:bg-slate-800 dark:bg-slate-700 dark:hover:bg-slate-600 text-white py-4 px-6 rounded-lg font-mono text-xs font-bold uppercase tracking-widest transition-all shadow-md hover:shadow-lg flex justify-center items-center gap-2"
             >
               {showDeepDive ? 'Hide Analysis' : 'Deep Dive Analysis'}
               <ChevronDown className={`h-4 w-4 transition-transform duration-300 ${showDeepDive ? 'rotate-180' : ''}`} />
             </button>
             <button 
               onClick={handleShare}
               className="bg-white hover:bg-slate-50 dark:bg-slate-800 dark:hover:bg-slate-700 border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-300 py-4 px-6 rounded-lg font-mono text-xs font-bold uppercase tracking-widest transition-all flex items-center justify-center gap-2"
             >
               <span>Share</span>
               <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                 <path d="M15 8a3 3 0 10-2.977-2.63l-4.94 2.47a3 3 0 100 4.319l4.94 2.47a3 3 0 10.895-1.789l-4.94-2.47a3.027 3.027 0 000-.74l4.94-2.47C13.456 7.68 14.19 8 15 8z" />
               </svg>
             </button>
          </div>
        </div>
      </div>

      {/* 2. DEEP DIVE (Collapsible) */}
      {showDeepDive && (
        <div className="animate-fade-in-up space-y-6">

          {/* Controls */}
          <div className="flex flex-wrap gap-4 justify-between items-center bg-white dark:bg-slate-900 p-4 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm transition-colors duration-300">
             <div className="flex items-center gap-3">
                <span className="text-[10px] font-mono uppercase font-bold text-slate-400">Analysis Mode:</span>
                <div className="flex bg-slate-100 dark:bg-slate-800 rounded-lg p-1">
                   <button 
                    onClick={() => setStressTestMode(false)}
                    className={`px-3 py-1.5 rounded-md text-[10px] font-mono font-bold uppercase transition-all ${!stressTestMode ? 'bg-white dark:bg-slate-700 text-slate-900 dark:text-white shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
                   >
                     Standard
                   </button>
                   <button 
                    onClick={() => setStressTestMode(true)}
                    className={`px-3 py-1.5 rounded-md text-[10px] font-mono font-bold uppercase transition-all ${stressTestMode ? 'bg-rose-500 text-white shadow-sm' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
                   >
                     Stress Test
                   </button>
                </div>
             </div>

             <div className="flex items-center gap-2">
                <button 
                  onClick={() => setShowHighlight(!showHighlight)}
                  className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-[10px] font-mono font-bold uppercase transition-all border ${showHighlight ? 'bg-emerald-50 dark:bg-emerald-900/20 border-emerald-200 dark:border-emerald-800 text-emerald-700 dark:text-emerald-400' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-500 hover:border-slate-300 dark:hover:border-slate-600'}`}
                >
                  <span className={`w-2 h-2 rounded-full ${showHighlight ? 'bg-emerald-500' : 'bg-slate-300'}`}></span>
                  Highlight Signal
                </button>
             </div>
          </div>

          {/* Highlighted Text View */}
          {showHighlight && (
             <div className="bg-white dark:bg-slate-900 p-8 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm animate-fade-in-up transition-colors duration-300">
                <div className="flex justify-between items-end mb-4">
                  <h4 className="text-xs font-bold font-mono uppercase text-slate-400">Signal Detection</h4>
                  <span className="text-[10px] font-mono text-emerald-600 dark:text-emerald-400 bg-emerald-50 dark:bg-emerald-900/20 px-2 py-1 rounded">Green = Binding Commitment</span>
                </div>
                <p className="font-serif text-xl leading-loose text-slate-300 dark:text-slate-600 selection:bg-emerald-100 dark:selection:bg-emerald-900/50 selection:text-emerald-900 dark:selection:text-emerald-100">
                  {statement_analysis.highlighted_text ? renderHighlightedText(statement_analysis.highlighted_text) : renderHighlightedText("**" + statement_analysis.original_text + "**")}
                </p>
             </div>
          )}

          {/* Checklist Grid */}
          <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm overflow-hidden animate-fade-in-up transition-colors duration-300">
            <div className="bg-slate-50 dark:bg-slate-800/50 px-5 py-3 border-b border-slate-200 dark:border-slate-700 flex justify-between items-center">
              <h4 className="text-xs font-bold font-mono uppercase text-slate-500 dark:text-slate-400">Structural Breakdown</h4>
              <span className="text-[10px] font-mono text-slate-400">Tap rows to expand</span>
            </div>
            <div>
              <ChecklistItem id="who" title={HUMAN_LABELS.who} element={elements.who} isStressTest={stressTestMode} />
              <ChecklistItem id="action" title={HUMAN_LABELS.action} element={elements.action} isStressTest={stressTestMode} />
              <ChecklistItem id="object" title={HUMAN_LABELS.object} element={elements.object} isStressTest={stressTestMode} />
              <ChecklistItem id="measure" title={HUMAN_LABELS.measure} element={elements.measure} isStressTest={stressTestMode} />
              <ChecklistItem id="when" title={HUMAN_LABELS.when} element={elements.when} isStressTest={stressTestMode} />
              <ChecklistItem id="premise" title={HUMAN_LABELS.premise} element={elements.premise} isStressTest={stressTestMode} />
            </div>
          </div>

           {/* Stress Test Footer */}
           {stressTestMode && (
             <div className="bg-rose-50 dark:bg-rose-900/20 text-rose-900 dark:text-rose-200 p-6 rounded-xl border border-rose-100 dark:border-rose-900/50 shadow-sm animate-fade-in-up flex gap-4 transition-colors duration-300">
                <div className="mt-1">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-rose-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                  </svg>
                </div>
                <div>
                  <h4 className="text-xs font-bold font-mono uppercase tracking-widest mb-1 text-rose-700 dark:text-rose-400">Time Decay Projection</h4>
                  <p className="font-sans text-sm leading-relaxed text-rose-800/80 dark:text-rose-300/80">
                     Items faded above lack structural binding (definitions, deadlines, or metrics). Without these anchors, the commitment is mathematically likely to be reinterpreted or ignored within 6 months.
                  </p>
                </div>
             </div>
           )}

           {/* 3. ASSUMPTIONS TO AVOID (New Feature) */}
           {assumptions.length > 0 && (
             <div className="animate-fade-in-up">
               <button 
                onClick={() => setShowAssumptions(!showAssumptions)}
                className="w-full flex justify-between items-center p-4 bg-amber-50 dark:bg-amber-900/10 border border-amber-200 dark:border-amber-800/30 rounded-lg hover:bg-amber-100 dark:hover:bg-amber-900/20 transition-all group"
               >
                 <div className="flex items-center gap-3">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 text-amber-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                    </svg>
                    <span className="text-xs font-bold font-mono uppercase tracking-widest text-amber-800 dark:text-amber-500">Assumptions to Avoid</span>
                 </div>
                 <ChevronDown className={`h-4 w-4 text-amber-500 transition-transform duration-300 ${showAssumptions ? 'rotate-180' : ''}`} />
               </button>

               {showAssumptions && (
                 <div className="mt-2 space-y-3 pl-4 border-l-2 border-amber-200 dark:border-amber-800/30">
                   {assumptions.map((item, idx) => (
                     <div key={idx} className="bg-white dark:bg-slate-900 p-4 rounded-lg border border-slate-200 dark:border-slate-800 shadow-sm animate-fade-in-up transition-colors duration-300" style={{ animationDelay: `${idx * 100}ms` }}>
                       <div className="mb-2">
                         <span className="text-[10px] font-mono uppercase text-slate-400">The Trap:</span>
                         <p className="font-bold text-sm text-slate-800 dark:text-slate-200">"{item.assumption}"</p>
                       </div>
                       <div className="mb-2">
                         <span className="text-[10px] font-mono uppercase text-slate-400">Structural Flaw:</span>
                         <p className="text-xs text-rose-600 dark:text-rose-400 italic">Because: {item.flaw}</p>
                       </div>
                       <div>
                         <span className="text-[10px] font-mono uppercase text-slate-400">Literal Reality:</span>
                         <p className="text-xs font-mono text-slate-600 dark:text-slate-400 bg-slate-50 dark:bg-slate-800 p-2 rounded mt-1">
                           {item.reality}
                         </p>
                       </div>
                     </div>
                   ))}
                 </div>
               )}
             </div>
           )}

        </div>
      )}
    </div>
  );
};

export default ClarityCard;

import React from 'react';
import { AnalysisHistoryItem, ClarityTier } from '../types';

interface AccountabilityLedgerProps {
  history: AnalysisHistoryItem[];
  onSelect: (item: AnalysisHistoryItem) => void;
  onClear: () => void;
}

const AccountabilityLedger: React.FC<AccountabilityLedgerProps> = ({ history, onSelect, onClear }) => {
  if (history.length === 0) return null;

  return (
