import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_PROMPT } from "../constants";
import { FullAnalysisResponse } from "../types";

// Helper to get API key safely
const getApiKey = (): string => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.error("API_KEY is not set in the environment.");
    return "";
  }
  return apiKey;
};

export const analyzeStatement = async (
  text: string, 
  fileData?: { mimeType: string; data: string }
): Promise<FullAnalysisResponse> => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API Key missing");

  const ai = new GoogleGenAI({ apiKey });

  // Construct contents based on whether file data is present
  let contents: any;
  if (fileData) {
    contents = {
      parts: [
        { inlineData: fileData },
        { text: text && text.trim() ? text : "Analyze the attached document for structural completeness and accountability." }
      ]
    };
  } else {
    contents = text;
  }

  // Using gemini-3-pro-preview for deep reasoning as requested ("Think more when needed")
  // and strictly enforcing JSON schema.
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: contents,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        thinkingConfig: { thinkingBudget: 32768 }, // Max thinking for pro
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            statement_analysis: {
              type: Type.OBJECT,
              properties: {
                original_text: { type: Type.STRING },
                highlighted_text: { type: Type.STRING },
                debate_reason: { type: Type.STRING },
                verification_requirements: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      requirement: { type: Type.STRING },
                      gap: { type: Type.STRING }
                    },
                    required: ["requirement", "gap"]
                  }
                },
                assumptions_to_avoid: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      assumption: { type: Type.STRING },
                      flaw: { type: Type.STRING },
                      reality: { type: Type.STRING }
                    },
                    required: ["assumption", "flaw", "reality"]
                  }
                },
                elements: {
                  type: Type.OBJECT,
                  properties: {
                    who: {
                      type: Type.OBJECT,
                      properties: {
                        content: { type: Type.STRING },
                        status: { type: Type.STRING, enum: ["CLEAR", "BROAD", "MISSING"] },
                        reasoning: { type: Type.STRING }
                      },
                      required: ["content", "status", "reasoning"]
                    },
                    action: {
                      type: Type.OBJECT,
                      properties: {
                        content: { type: Type.STRING },
                        status: { type: Type.STRING, enum: ["CLEAR", "BROAD", "MISSING"] },
                        reasoning: { type: Type.STRING }
                      },
                      required: ["content", "status", "reasoning"]
                    },
                    object: {
                      type: Type.OBJECT,
                      properties: {
                        content: { type: Type.STRING },
                        status: { type: Type.STRING, enum: ["CLEAR", "BROAD", "MISSING"] },
                        reasoning: { type: Type.STRING }
                      },
                      required: ["content", "status", "reasoning"]
                    },
                    measure: {
                      type: Type.OBJECT,
                      properties: {
                        content: { type: Type.STRING },
                        status: { type: Type.STRING, enum: ["CLEAR", "BROAD", "MISSING"] },
                        reasoning: { type: Type.STRING }
                      },
                      required: ["content", "status", "reasoning"]
                    },
                    when: {
                      type: Type.OBJECT,
                      properties: {
                        content: { type: Type.STRING },
                        status: { type: Type.STRING, enum: ["CLEAR", "BROAD", "MISSING"] },
                        reasoning: { type: Type.STRING }
                      },
                      required: ["content", "status", "reasoning"]
                    },
                    premise: {
                      type: Type.OBJECT,
                      properties: {
                        content: { type: Type.STRING },
                        status: { type: Type.STRING, enum: ["CLEAR", "BROAD", "MISSING"] },
                        reasoning: { type: Type.STRING }
                      },
                      required: ["content", "status", "reasoning"]
                    }
                  },
                  required: ["who", "action", "object", "measure", "when", "premise"]
                }
              },
              required: ["original_text", "highlighted_text", "debate_reason", "assumptions_to_avoid", "verification_requirements", "elements"]
            },
            literal_translation: { type: Type.STRING }
          },
          required: ["statement_analysis", "literal_translation"]
        },
      },
    });

    if (!response.text) {
      throw new Error("Empty response from AI");
    }

    return JSON.parse(response.text) as FullAnalysisResponse;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

export const streamChat = async function* (history: { role: string; parts: { text: string }[] }[], newMessage: string) {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API Key missing");
  const ai = new GoogleGenAI({ apiKey });

  const chat = ai.chats.create({
    model: 'gemini-3-pro-preview', // Consistent model
    config: {
      systemInstruction: SYSTEM_PROMPT,
    },
    history: history
  });

  const result = await chat.sendMessageStream({ message: newMessage });
  for await (const chunk of result) {
    yield chunk.text;
  }
};

import React, { useState, useRef } from 'react';

interface InputSectionProps {
  onAnalyze: (text: string, fileData?: { mimeType: string, data: string }) => void;
  isLoading: boolean;
}

const InputSection: React.FC<InputSectionProps> = ({ onAnalyze, isLoading }) => {
  const [text, setText] = useState('');
  const [file, setFile] = useState<{ name: string; mimeType: string; data: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (text.trim() || file) {
      onAnalyze(text, file ? { mimeType: file.mimeType, data: file.data } : undefined);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (!selectedFile) return;

    // Check strict PDF type
    if (selectedFile.type !== 'application/pdf') {
      alert("Please upload a PDF document.");
      return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      const result = event.target?.result as string;
      // Extract base64 part (remove data:application/pdf;base64, prefix)
      const base64Data = result.split(',')[1];
      setFile({
        name: selectedFile.name,
        mimeType: selectedFile.type,
        data: base64Data
      });
    };
    reader.readAsDataURL(selectedFile);
  };

  const handleRemoveFile = () => {
    setFile(null);
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  return (
    <section className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 shadow-sm rounded-none p-6 md:p-8 mb-8 transition-colors duration-300">
      <form onSubmit={handleSubmit}>
        <div className="flex justify-between items-center mb-3">
          <label htmlFor="statement" className="block text-xs font-bold font-mono text-slate-500 dark:text-slate-400 uppercase tracking-wider">
            Input Statement / Document
          </label>
          {file && (
            <div className="flex items-center gap-2 bg-indigo-50 dark:bg-indigo-900/20 text-indigo-700 dark:text-indigo-300 px-3 py-1 rounded-full text-xs font-mono animate-fade-in-up">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
              </svg>
              <span className="truncate max-w-[150px] md:max-w-[300px]">{file.name}</span>
              <button 
                type="button" 
                onClick={handleRemoveFile} 
                className="hover:text-rose-500 transition-colors ml-1"
                aria-label="Remove file"
              >
                &times;
              </button>
            </div>
          )}
        </div>

        <textarea
          id="statement"
          className="w-full h-40 p-4 font-mono text-sm bg-slate-50 dark:bg-slate-800 border border-slate-300 dark:border-slate-700 focus:border-slate-900 dark:focus:border-slate-500 focus:ring-0 transition-colors resize-none rounded-sm text-slate-900 dark:text-slate-100 placeholder:text-slate-400 dark:placeholder:text-slate-500"
          placeholder="Paste headline, speech snippet, or attach a PDF document..."
          maxLength={10000}
          value={text}
          onChange={(e) => setText(e.target.value)}
          disabled={isLoading}
        />

        <div className="flex flex-col md:flex-row justify-between items-center mt-4 gap-4">
          <div className="flex items-center gap-4 w-full md:w-auto">
             <span className="text-xs font-mono text-slate-400 dark:text-slate-500">
              {text.length}/10000 Chars
             </span>

             <input 
               type="file" 
               ref={fileInputRef} 
               accept="application/pdf" 
               onChange={handleFileChange} 
               className="hidden" 
             />
             <button
               type="button"
               onClick={() => fileInputRef.current?.click()}
               disabled={isLoading || !!file}
               className={`flex items-center gap-2 text-xs font-mono font-bold uppercase tracking-wide px-3 py-1.5 rounded-sm border transition-all
                 ${file ? 'text-slate-300 border-slate-200 dark:border-slate-800 cursor-not-allowed' : 'text-slate-600 dark:text-slate-400 border-slate-300 dark:border-slate-600 hover:bg-slate-100 dark:hover:bg-slate-800'}`}
             >
               <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13" />
               </svg>
               Attach PDF
             </button>
          </div>

          <button
            type="submit"
            disabled={isLoading || (!text.trim() && !file)}
            className={`w-full md:w-auto px-8 py-3 font-mono text-sm font-bold uppercase tracking-wide text-white transition-all 
              ${isLoading || (!text.trim() && !file) ? 'bg-slate-300 dark:bg-slate-700 cursor-not-allowed' : 'bg-slate-900 dark:bg-slate-700 hover:bg-slate-800 dark:hover:bg-slate-600'}`}
          >
            {isLoading ? 'Scanning...' : 'Analyze'}
          </button>
        </div>
      </form>
    </section>
  );
};

export default InputSection;

import React, { useState, useEffect, useRef } from 'react';
import Header from './components/Header';
import InputSection from './components/InputSection';
import ClarityCard from './components/ClarityCard';
import ChatWidget from './components/ChatWidget';
import AccountabilityLedger from './components/AccountabilityLedger';
import { analyzeStatement } from './services/geminiService';
import { 
  FullAnalysisResponse, 
  CalculatedScore, 
  ElementStatus, 
  ClarityTier,
  StatementAnalysis,
  AnalysisHistoryItem 
} from './types';
import { WEIGHTS, STATUS_PENALTY_MULTIPLIER, MAX_SCORE, TIER_THRESHOLDS } from './constants';

// Skeleton Loader Component
const AnalysisSkeleton = () => (
  <div className="space-y-6 animate-pulse">
    <div className="bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl p-8 h-96 w-full relative overflow-hidden transition-colors">
      <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-r from-transparent via-slate-50 dark:via-slate-700/50 to-transparent -translate-x-full animate-[shimmer_2s_infinite]"></div>
      <div className="flex justify-between mb-8">
        <div className="space-y-3">
          <div className="h-3 bg-slate-200 dark:bg-slate-700 rounded w-24"></div>
          <div className="h-8 bg-slate-200 dark:bg-slate-700 rounded w-48"></div>
        </div>
        <div className="space-y-3 items-end flex flex-col">
          <div className="h-10 bg-slate-200 dark:bg-slate-700 rounded w-20"></div>
          <div className="h-3 bg-slate-200 dark:bg-slate-700 rounded w-32"></div>
        </div>
      </div>
      <div className="space-y-4">
         <div className="h-4 bg-slate-200 dark:bg-slate-700 rounded w-full"></div>
         <div className="h-4 bg-slate-200 dark:bg-slate-700 rounded w-3/4"></div>
      </div>
      <div className="mt-12 h-24 bg-slate-100 dark:bg-slate-700/50 rounded-lg"></div>
    </div>
  </div>
);

const App: React.FC = () => {
  const [analysis, setAnalysis] = useState<FullAnalysisResponse | null>(null);
  const [score, setScore] = useState<CalculatedScore | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [history, setHistory] = useState<AnalysisHistoryItem[]>([]);
  const [isDarkMode, setIsDarkMode] = useState(false);

  const resultRef = useRef<HTMLDivElement>(null);

  // Initialize Dark Mode based on system preference or local storage
  useEffect(() => {
    const savedTheme = localStorage.getItem('clarity_theme');
    if (savedTheme === 'dark' || (!savedTheme && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      setIsDarkMode(true);
      document.documentElement.classList.add('dark');
    } else {
      setIsDarkMode(false);
      document.documentElement.classList.remove('dark');
    }
  }, []);

  const toggleDarkMode = () => {
    if (isDarkMode) {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('clarity_theme', 'light');
      setIsDarkMode(false);
    } else {
      document.documentElement.classList.add('dark');
      localStorage.setItem('clarity_theme', 'dark');
      setIsDarkMode(true);
    }
  };

  // Load history from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem('clarity_ledger');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse history");
      }
    }
  }, []);

  const saveToHistory = (newItem: AnalysisHistoryItem) => {
    const newHistory = [...history, newItem];
    // Keep last 10 items
    if (newHistory.length > 10) newHistory.shift(); 
    setHistory(newHistory);
    localStorage.setItem('clarity_ledger', JSON.stringify(newHistory));
  };

  const clearHistory = () => {
    setHistory([]);
    localStorage.removeItem('clarity_ledger');
  };

  const calculateScore = (analysisData: StatementAnalysis): CalculatedScore => {
    const els = analysisData.elements;
    let rawPenaltyScore = 0;
    let missingCount = 0;

    // Helper to calc element score
    const calcElement = (status: ElementStatus, weight: number) => {
      const penalty = STATUS_PENALTY_MULTIPLIER[status];
      if (status === ElementStatus.MISSING) missingCount++;
      return weight * penalty;
    };

    rawPenaltyScore += calcElement(els.who.status as ElementStatus, WEIGHTS.who);
    rawPenaltyScore += calcElement(els.action.status as ElementStatus, WEIGHTS.action);
    rawPenaltyScore += calcElement(els.object.status as ElementStatus, WEIGHTS.object);
    rawPenaltyScore += calcElement(els.measure.status as ElementStatus, WEIGHTS.measure);
    rawPenaltyScore += calcElement(els.when.status as ElementStatus, WEIGHTS.when);
    rawPenaltyScore += calcElement(els.premise.status as ElementStatus, WEIGHTS.premise);

    let finalAmbiguityScore = (rawPenaltyScore / MAX_SCORE) * 10;

    // Rule D: Hierarchy of Missing Elements
    // If WHO and ACTION are both MISSING, Score is 10.0
    const criticalFailure = els.who.status === ElementStatus.MISSING && els.action.status === ElementStatus.MISSING;
    if (criticalFailure) {
      finalAmbiguityScore = 10.0;
    }

    let tier = ClarityTier.TIER_1;
    if (finalAmbiguityScore > TIER_THRESHOLDS.TIER_2_LIMIT) {
      tier = ClarityTier.TIER_3;
    } else if (finalAmbiguityScore > TIER_THRESHOLDS.TIER_1_LIMIT) {
      tier = ClarityTier.TIER_2;
    }

    // Rule C: The Tier Floor Rule (3 Strikes)
    // If >= 3 elements are MISSING, auto Tier 3
    if (missingCount >= 3) {
      tier = ClarityTier.TIER_3;
    }

    return {
      rawPenaltyScore,
      finalAmbiguityScore,
      tier,
      missingCount,
      criticalFailure
    };
  };

  const handleAnalyze = async (text: string, fileData?: { mimeType: string, data: string }) => {
    setIsLoading(true);
    setError(null);
    setAnalysis(null);
    setScore(null);

    // Scroll slightly to prepare for result
    if (window.innerWidth < 768) {
       window.scrollTo({ top: 100, behavior: 'smooth' });
    }

    try {
      const result = await analyzeStatement(text, fileData);
      setAnalysis(result);
      const computedScore = calculateScore(result.statement_analysis);
      setScore(computedScore);

      // Save to ledger
      const historyItem: AnalysisHistoryItem = {
        id: Date.now().toString(),
        timestamp: Date.now(),
        text: fileData ? `[Document] ${fileData.mimeType === 'application/pdf' ? 'PDF Analysis' : 'File'} ${text ? ' + ' + text : ''}` : text,
        score: computedScore,
        analysis: result
      };
      saveToHistory(historyItem);

      // Auto-scroll to result after short delay to allow render
      setTimeout(() => {
        resultRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
      }, 100);

    } catch (err) {
      console.error(err);
      setError("Analysis failed. Please try again. Ensure your API Key is valid and the file is supported.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleSelectHistory = (item: AnalysisHistoryItem) => {
    setAnalysis(item.analysis);
    setScore(item.score);
    setTimeout(() => {
        resultRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 100);
  };

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 flex flex-col font-sans text-slate-900 dark:text-slate-100 selection:bg-slate-200 dark:selection:bg-slate-700 transition-colors duration-300">
      <Header isDarkMode={isDarkMode} toggleDarkMode={toggleDarkMode} />

      <main className="flex-1 container mx-auto px-4 max-w-4xl py-8 md:py-12">

        <InputSection onAnalyze={handleAnalyze} isLoading={isLoading} />

        {error && (
           <div className="bg-rose-50 dark:bg-rose-900/20 border-l-4 border-rose-500 text-rose-800 dark:text-rose-200 p-4 mb-8 font-mono text-sm rounded-r" role="alert">
             <p className="font-bold mb-1">Analysis Error</p>
             <p>{error}</p>
           </div>
        )}

        <div ref={resultRef}>
          {isLoading && <AnalysisSkeleton />}

          {analysis && score && (
            <ClarityCard analysis={analysis} score={score} />
          )}
        </div>

        <div className="mt-12 border-t border-slate-200 dark:border-slate-800 pt-8">
           <AccountabilityLedger 
            history={history} 
            onSelect={handleSelectHistory} 
            onClear={clearHistory} 
          />
        </div>

        {!analysis && !isLoading && !error && history.length === 0 && (
           <div className="text-center py-24 text-slate-400 dark:text-slate-500">
             <p className="font-mono text-xs uppercase tracking-widest mb-3 opacity-60">System Ready</p>
             <p className="font-sans text-sm md:text-base max-w-md mx-auto leading-relaxed">
               Paste a corporate statement, political promise, or attach a document (PDF) above to begin forensic structural analysis.
             </p>
           </div>
        )}
      </main>

      <footer className="bg-slate-50 dark:bg-slate-900 text-slate-400 dark:text-slate-500 py-8 border-t border-slate-200 dark:border-slate-800 transition-colors duration-300">
        <div className="container mx-auto px-4 max-w-4xl text-center">
          <p className="font-mono text-[10px] uppercase tracking-widest opacity-60">
            Powered by Gemini 3 Pro • Deep Reasoning Logic
          </p>
        </div>
      </footer>

      <ChatWidget />
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_PROMPT } from "../constants";
import { FullAnalysisResponse } from "../types";

// Helper to get API key safely
const getApiKey = (): string => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.error("API_KEY is not set in the environment.");
    return "";
  }
  return apiKey;
};

// New function to fetch content via URL using Google Search Grounding
export const fetchUrlContent = async (url: string): Promise<string> => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API Key missing");

  const ai = new GoogleGenAI({ apiKey });

  // Use gemini-2.5-flash for fast retrieval with search tools
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: `Retrieve and read the article at this URL: ${url}. 

    Task: Return a comprehensive transcript of the text content. 
    - Preserve original wording of claims, promises, and commitments.
    - If the full text is not directly accessible, provide a detailed summary of the key statements and quotes.
    - Do not analyze or judge the content yet, just provide the raw text for downstream analysis.`,
    config: {
      tools: [{ googleSearch: {} }],
      // Note: responseMimeType and responseSchema are NOT allowed with googleSearch
    },
  });

  if (!response.text) {
    throw new Error("Could not retrieve content from URL.");
  }

  return response.text;
};

export const analyzeStatement = async (
  text: string, 
  fileData?: { mimeType: string; data: string }
): Promise<FullAnalysisResponse> => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API Key missing");

  const ai = new GoogleGenAI({ apiKey });

  // Construct contents based on whether file data is present
  let contents: any;
  if (fileData) {
    contents = {
      parts: [
        { inlineData: fileData },
        { text: text && text.trim() ? text : "Analyze the attached document for structural completeness and accountability." }
      ]
    };
  } else {
    contents = text;
  }

  // Using gemini-3-pro-preview for deep reasoning as requested ("Think more when needed")
  // and strictly enforcing JSON schema.
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: contents,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        thinkingConfig: { thinkingBudget: 32768 }, // Max thinking for pro
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            statement_analysis: {
              type: Type.OBJECT,
              properties: {
                original_text: { type: Type.STRING },
                highlighted_text: { type: Type.STRING },
                debate_reason: { type: Type.STRING },
                verification_requirements: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      requirement: { type: Type.STRING },
                      gap: { type: Type.STRING }
                    },
                    required: ["requirement", "gap"]
                  }
                },
                assumptions_to_avoid: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      assumption: { type: Type.STRING },
                      flaw: { type: Type.STRING },
                      reality: { type: Type.STRING }
                    },
                    required: ["assumption", "flaw", "reality"]
                  }
                },
                elements: {
                  type: Type.OBJECT,
                  properties: {
                    who: {
                      type: Type.OBJECT,
                      properties: {
                        content: { type: Type.STRING },
                        status: { type: Type.STRING, enum: ["CLEAR", "BROAD", "MISSING"] },
                        reasoning: { type: Type.STRING }
                      },
                      required: ["content", "status", "reasoning"]
                    },
                    action: {
                      type: Type.OBJECT,
                      properties: {
                        content: { type: Type.STRING },
                        status: { type: Type.STRING, enum: ["CLEAR", "BROAD", "MISSING"] },
                        reasoning: { type: Type.STRING }
                      },
                      required: ["content", "status", "reasoning"]
                    },
                    object: {
                      type: Type.OBJECT,
                      properties: {
                        content: { type: Type.STRING },
                        status: { type: Type.STRING, enum: ["CLEAR", "BROAD", "MISSING"] },
                        reasoning: { type: Type.STRING }
                      },
                      required: ["content", "status", "reasoning"]
                    },
                    measure: {
                      type: Type.OBJECT,
                      properties: {
                        content: { type: Type.STRING },
                        status: { type: Type.STRING, enum: ["CLEAR", "BROAD", "MISSING"] },
                        reasoning: { type: Type.STRING }
                      },
                      required: ["content", "status", "reasoning"]
                    },
                    when: {
                      type: Type.OBJECT,
                      properties: {
                        content: { type: Type.STRING },
                        status: { type: Type.STRING, enum: ["CLEAR", "BROAD", "MISSING"] },
                        reasoning: { type: Type.STRING }
                      },
                      required: ["content", "status", "reasoning"]
                    },
                    premise: {
                      type: Type.OBJECT,
                      properties: {
                        content: { type: Type.STRING },
                        status: { type: Type.STRING, enum: ["CLEAR", "BROAD", "MISSING"] },
                        reasoning: { type: Type.STRING }
                      },
                      required: ["content", "status", "reasoning"]
                    }
                  },
                  required: ["who", "action", "object", "measure", "when", "premise"]
                }
              },
              required: ["original_text", "highlighted_text", "debate_reason", "assumptions_to_avoid", "verification_requirements", "elements"]
            },
            literal_translation: { type: Type.STRING }
          },
          required: ["statement_analysis", "literal_translation"]
        },
      },
    });

    if (!response.text) {
      throw new Error("Empty response from AI");
    }

    return JSON.parse(response.text) as FullAnalysisResponse;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

export const streamChat = async function* (history: { role: string; parts: { text: string }[] }[], newMessage: string) {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API Key missing");
  const ai = new GoogleGenAI({ apiKey });

  const chat = ai.chats.create({
    model: 'gemini-3-pro-preview', // Consistent model
    config: {
      systemInstruction: SYSTEM_PROMPT,
    },
    history: history
  });

  const result = await chat.sendMessageStream({ message: newMessage });
  for await (const chunk of result) {
    yield chunk.text;
  }
};

import React, { useState, useRef } from 'react';

interface InputSectionProps {
  onAnalyze: (text: string, fileData?: { mimeType: string, data: string }, url?: string) => void;
  isLoading: boolean;
}

type InputMode = 'direct' | 'url';

const InputSection: React.FC<InputSectionProps> = ({ onAnalyze, isLoading }) => {
  const [mode, setMode] = useState<InputMode>('direct');
  const [text, setText] = useState('');
  const [url, setUrl] = useState('');
  const [file, setFile] = useState<{ name: string; mimeType: string; data: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (mode === 'direct') {
      if (text.trim() || file) {
        onAnalyze(text, file ? { mimeType: file.mimeType, data: file.data } : undefined);
      }
    } else {
      if (url.trim()) {
        onAnalyze('', undefined, url);
      }
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (!selectedFile) return;

    // Check strict PDF type
    if (selectedFile.type !== 'application/pdf') {
      alert("Please upload a PDF document.");
      return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      const result = event.target?.result as string;
      // Extract base64 part (remove data:application/pdf;base64, prefix)
      const base64Data = result.split(',')[1];
      setFile({
        name: selectedFile.name,
        mimeType: selectedFile.type,
        data: base64Data
      });
    };
    reader.readAsDataURL(selectedFile);
  };

  const handleRemoveFile = () => {
    setFile(null);
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  return (
    <section className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 shadow-sm rounded-none p-6 md:p-8 mb-8 transition-colors duration-300">

      {/* Mode Tabs */}
      <div className="flex border-b border-slate-100 dark:border-slate-800 mb-6">
        <button
          type="button"
          onClick={() => setMode('direct')}
          className={`pb-3 px-4 text-xs font-bold font-mono uppercase tracking-widest transition-colors relative
            ${mode === 'direct' ? 'text-slate-900 dark:text-white' : 'text-slate-400 dark:text-slate-600 hover:text-slate-600 dark:hover:text-slate-400'}`}
        >
          Text / PDF
          {mode === 'direct' && <span className="absolute bottom-0 left-0 w-full h-0.5 bg-slate-900 dark:bg-white"></span>}
        </button>
        <button
          type="button"
          onClick={() => setMode('url')}
          className={`pb-3 px-4 text-xs font-bold font-mono uppercase tracking-widest transition-colors relative
            ${mode === 'url' ? 'text-indigo-600 dark:text-indigo-400' : 'text-slate-400 dark:text-slate-600 hover:text-slate-600 dark:hover:text-slate-400'}`}
        >
          URL Search
          {mode === 'url' && <span className="absolute bottom-0 left-0 w-full h-0.5 bg-indigo-600 dark:bg-indigo-400"></span>}
        </button>
      </div>

      <form onSubmit={handleSubmit}>

        {mode === 'direct' ? (
          <div className="animate-fade-in-up">
            <div className="flex justify-between items-center mb-3">
