const ClarityCard: React.FC<ClarityCardProps> = ({ analysis, score }) => {
  const [showDeepDive, setShowDeepDive] = useState(false);
  const [showHighlight, setShowHighlight] = useState(false);
  const [stressTestMode, setStressTestMode] = useState(false);
  const [showAssumptions, setShowAssumptions] = useState(false);
  const [showVerification, setShowVerification] = useState(false);
  const [showSticky, setShowSticky] = useState(false);
  const [showWorstLines, setShowWorstLines] = useState(false);

  const verdictRef = useRef<HTMLDivElement>(null);
  const worstLineRef = useRef<HTMLDivElement>(null);

  const { statement_analysis } = analysis;
  const elements = statement_analysis.elements;
  const clearCount = (Object.values(elements) as AnalysisElement[]).filter(e => e.status === ElementStatus.CLEAR).length;
  const assumptions = statement_analysis.assumptions_to_avoid || [];
  const verifications = statement_analysis.verification_requirements || [];
  const risk = statement_analysis.risk_profile;

  // Detect if this is a document analysis (total claims > 1)
  const isDocumentAnalysis = risk && (risk.tier_1_count + risk.tier_2_count + risk.tier_3_count > 1);
  const totalClaims = risk ? risk.tier_1_count + risk.tier_2_count + risk.tier_3_count : 0;

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        setShowSticky(!entry.isIntersecting);
      },
      { threshold: 0.2 }
    );

    if (verdictRef.current) {
      observer.observe(verdictRef.current);
    }

    return () => {
      if (verdictRef.current) observer.unobserve(verdictRef.current);
    };
  }, []);

  const handleShare = () => {
    if (navigator.share) {
      navigator.share({
        title: 'Clarity Analysis',
        text: `Verdict: ${score.tier} (${score.finalAmbiguityScore}/10). ${analysis.literal_translation}`,
      }).catch(console.error);
    } else {
      // Basic copy fallback
      navigator.clipboard.writeText(`Verdict: ${score.tier}. ${analysis.literal_translation}`);
      alert("Summary copied to clipboard.");
    }
  };

  const handleShowWorst = () => {
    setShowWorstLines(true);
    setTimeout(() => {
      worstLineRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }, 100);
  };

  const renderHighlightedText = (text: string) => {
    const parts = text.split(/(\*\*.*?\*\*)/g);
    return parts.map((part, i) => {
      if (part.startsWith('**') && part.endsWith('**')) {
        return <span key={i} className="bg-emerald-100/80 dark:bg-emerald-900/60 text-emerald-900 dark:text-emerald-300 font-semibold px-1 py-0.5 rounded-sm box-decoration-clone">{part.slice(2, -2)}</span>;
      }
      return <span key={i} className="text-slate-400 dark:text-slate-500 transition-opacity duration-500">{part}</span>;
    });
  };

  return (
    <div className="space-y-6 relative pb-24">

      {/* Sticky Context Pill - Appears when scrolling past verdict */}
      {showSticky && <StickyPill score={score} />}

      {/* 1. VERDICT CARD (Hero) */}
      <div ref={verdictRef} className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 shadow-sm rounded-xl overflow-hidden animate-fade-in-up transition-colors duration-300">
        {/* Header */}
        <div className="bg-slate-50/50 dark:bg-slate-800/50 px-6 py-5 border-b border-slate-100 dark:border-slate-800 flex justify-between items-start">
          <div>
            <span className="block text-[10px] font-mono uppercase tracking-widest text-slate-400 mb-1">Verdict</span>
            <div className={`text-xl md:text-2xl font-bold font-mono uppercase flex items-center gap-2 tracking-tight
              ${score.tier === ClarityTier.TIER_1 ? 'text-emerald-700 dark:text-emerald-400' : 
                score.tier === ClarityTier.TIER_2 ? 'text-amber-600 dark:text-amber-400' : 
                'text-rose-600 dark:text-rose-400'}`}>
               {score.tier === ClarityTier.TIER_1 ? <StatusIcon status={ElementStatus.CLEAR} className="h-6 w-6" /> : 
                score.tier === ClarityTier.TIER_2 ? <StatusIcon status={ElementStatus.BROAD} className="h-6 w-6" /> : 
                <StatusIcon status={ElementStatus.MISSING} className="h-6 w-6" />}
               {score.tier}
            </div>
          </div>
          <div className="text-right">
             <div className="text-4xl font-bold font-mono text-slate-900 dark:text-white tracking-tighter">{score.finalAmbiguityScore.toFixed(1)}</div>
             <div className="text-[10px] font-mono uppercase text-slate-400 mt-1">Ambiguity Score</div>
          </div>
        </div>

        {/* Content Body */}
        <div className="p-6 md:p-8">

          {/* RISK ANALYSIS DASHBOARD (For Documents) */}
          {isDocumentAnalysis && risk && (
            <div className="mb-8 p-5 bg-slate-50 dark:bg-slate-800/50 border border-slate-200 dark:border-slate-700 rounded-lg animate-fade-in-up">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-xs font-bold font-mono uppercase text-slate-500 dark:text-slate-400 tracking-wider">Document Risk Profile</h3>
                <span className="text-[10px] font-mono bg-slate-200 dark:bg-slate-700 px-2 py-1 rounded text-slate-600 dark:text-slate-300">
                  {totalClaims} Claims Analyzed
                </span>
              </div>

              {/* Distribution Bar */}
              <div className="flex h-6 w-full rounded-md overflow-hidden mb-4 shadow-sm">
                <div style={{ width: `${(risk.tier_1_count / totalClaims) * 100}%` }} className="bg-emerald-500 h-full relative group">
                  <div className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white opacity-0 group-hover:opacity-100 transition-opacity">
                    {risk.tier_1_count} Clear
                  </div>
                </div>
                <div style={{ width: `${(risk.tier_2_count / totalClaims) * 100}%` }} className="bg-amber-500 h-full relative group">
                   <div className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white opacity-0 group-hover:opacity-100 transition-opacity">
                    {risk.tier_2_count} Broad
                  </div>
                </div>
                <div style={{ width: `${(risk.tier_3_count / totalClaims) * 100}%` }} className="bg-rose-500 h-full relative group">
                   <div className="absolute inset-0 flex items-center justify-center text-[10px] font-bold text-white opacity-0 group-hover:opacity-100 transition-opacity">
                    {risk.tier_3_count} Vague
                  </div>
                </div>
              </div>

              <div className="flex justify-between text-[10px] font-mono uppercase text-slate-400 mb-6">
                <div className="flex items-center gap-1"><div className="w-2 h-2 bg-emerald-500 rounded-full"></div>Tier 1 ({risk.tier_1_count})</div>
                <div className="flex items-center gap-1"><div className="w-2 h-2 bg-amber-500 rounded-full"></div>Tier 2 ({risk.tier_2_count})</div>
                <div className="flex items-center gap-1"><div className="w-2 h-2 bg-rose-500 rounded-full"></div>Tier 3 ({risk.tier_3_count})</div>
              </div>

              <div className="flex flex-col md:flex-row gap-4">
                {/* Unverifiable Badge */}
                <div className="flex-1 bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 p-3 rounded flex items-center gap-3">
                  <div className="bg-rose-100 dark:bg-rose-900/30 p-2 rounded-full text-rose-600 dark:text-rose-400">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                    </svg>
                  </div>
                  <div>
                    <div className="text-lg font-bold font-mono text-slate-900 dark:text-white">{risk.unverifiable_claim_count}</div>
                    <div className="text-[10px] uppercase font-mono text-slate-500">Unverifiable Claims</div>
                  </div>
                </div>

                {/* Show Worst Line Button */}
                <button 
                  onClick={handleShowWorst}
                  className="flex-1 bg-rose-500 hover:bg-rose-600 text-white p-3 rounded font-mono text-xs font-bold uppercase tracking-wide transition-colors flex items-center justify-center gap-2 shadow-sm"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                     <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
                  </svg>
                  Show Me The Worst Line
                </button>
              </div>

              {/* Worst Line Reveal */}
              {showWorstLines && risk.worst_lines.length > 0 && (
                <div ref={worstLineRef} className="mt-6 pt-6 border-t border-slate-200 dark:border-slate-700 animate-fade-in-up">
                  <h4 className="text-xs font-bold font-mono uppercase text-rose-600 dark:text-rose-400 mb-3 tracking-wider flex items-center gap-2">
                    <span className="w-2 h-2 rounded-full bg-rose-500 animate-pulse"></span>
                    Critical Failure Detected
                  </h4>
                  <div className="space-y-3">
                    {risk.worst_lines.map((line, idx) => (
                      <div key={idx} className="bg-rose-50 dark:bg-rose-900/10 border-l-4 border-rose-500 p-4 rounded-r-md">
                        <p className="font-serif text-lg italic text-slate-800 dark:text-slate-200 mb-2">
                          "{line.text}"
                        </p>
                        <p className="text-xs font-mono text-rose-800 dark:text-rose-300">
                          <span className="font-bold">FLAW:</span> {line.flaw}
                        </p>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}

          {/* Commitment Density Meter (Simplified for Single Mode, or Condensed if Doc mode) */}
