import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_PROMPT } from "../constants";
import { FullAnalysisResponse } from "../types";

// Helper to get API key safely
const getApiKey = (): string => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.error("API_KEY is not set in the environment.");
    return "";
  }
  return apiKey;
};

// New function to fetch content via URL using Google Search Grounding
export const fetchUrlContent = async (url: string): Promise<string> => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API Key missing");

  const ai = new GoogleGenAI({ apiKey });

  // Use gemini-2.5-flash for fast retrieval with search tools
  // Improved prompt to handle URLs that might not be directly indexable
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: `I need to analyze the text content of the following article for a logic check.

    URL: ${url}

    Action:
    1. Use Google Search to find the text of this article. 
    2. If the direct URL doesn't yield a result, search for the article title or keywords embedded in the URL to find the content.
    3. Return a comprehensive summary or transcript of the claims, promises, and factual assertions made in the text.

    Constraint:
    - Do NOT provide a generic description of the website.
    - Provide the actual content/text of the article.`,
    config: {
      tools: [{ googleSearch: {} }],
      // Note: responseMimeType and responseSchema are NOT allowed with googleSearch
    },
  });

  if (!response.text) {
    // If no text, check if we have grounding metadata but no generated text (edge case)
    if (response.candidates?.[0]?.groundingMetadata) {
       return "Found related content but could not generate a transcript. Please try pasting the text directly.";
    }
    throw new Error("Google Search could not retrieve text for this URL. The content might be behind a paywall or not indexed.");
  }

  return response.text;
};

export const analyzeStatement = async (
  text: string, 
  fileData?: { mimeType: string; data: string }
): Promise<FullAnalysisResponse> => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API Key missing");

  const ai = new GoogleGenAI({ apiKey });

  // Construct contents based on whether file data is present
  let contents: any;
  if (fileData) {
    contents = {
      parts: [
        { inlineData: fileData },
        { text: text && text.trim() ? text : "Analyze the attached document for structural completeness and accountability." }
      ]
    };
  } else {
    contents = text;
  }

  // Using gemini-3-pro-preview for deep reasoning
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: contents,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        thinkingConfig: { thinkingBudget: 32768 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            statement_analysis: {
              type: Type.OBJECT,
              properties: {
                original_text: { type: Type.STRING },
                highlighted_text: { type: Type.STRING },
                debate_reason: { type: Type.STRING },
                risk_profile: {
                  type: Type.OBJECT,
                  properties: {
                    tier_1_count: { type: Type.NUMBER },
                    tier_2_count: { type: Type.NUMBER },
                    tier_3_count: { type: Type.NUMBER },
                    unverifiable_claim_count: { type: Type.NUMBER },
                    worst_lines: {
                      type: Type.ARRAY,
                      items: {
                        type: Type.OBJECT,
                        properties: {
                          text: { type: Type.STRING },
                          flaw: { type: Type.STRING }
                        },
                        required: ["text", "flaw"]
                      }
                    }
                  },
                  required: ["tier_1_count", "tier_2_count", "tier_3_count", "unverifiable_claim_count", "worst_lines"]
                },
                verification_requirements: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      requirement: { type: Type.STRING },
                      gap: { type: Type.STRING }
                    },
                    required: ["requirement", "gap"]
                  }
                },
                assumptions_to_avoid: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      assumption: { type: Type.STRING },
                      flaw: { type: Type.STRING },
                      reality: { type: Type.STRING }
                    },
                    required: ["assumption", "flaw", "reality"]
                  }
                },
                elements: {
                  type: Type.OBJECT,
                  properties: {
                    who: {
                      type: Type.OBJECT,
                      properties: {
                        content: { type: Type.STRING },
                        status: { type: Type.STRING, enum: ["CLEAR", "BROAD", "MISSING"] },
                        reasoning: { type: Type.STRING }
                      },
                      required: ["content", "status", "reasoning"]
                    },
                    action: {
                      type: Type.OBJECT,
                      properties: {
                        content: { type: Type.STRING },
                        status: { type: Type.STRING, enum: ["CLEAR", "BROAD", "MISSING"] },
                        reasoning: { type: Type.STRING }
                      },
                      required: ["content", "status", "reasoning"]
                    },
                    object: {
                      type: Type.OBJECT,
                      properties: {
                        content: { type: Type.STRING },
                        status: { type: Type.STRING, enum: ["CLEAR", "BROAD", "MISSING"] },
                        reasoning: { type: Type.STRING }
                      },
                      required: ["content", "status", "reasoning"]
                    },
                    measure: {
                      type: Type.OBJECT,
                      properties: {
                        content: { type: Type.STRING },
                        status: { type: Type.STRING, enum: ["CLEAR", "BROAD", "MISSING"] },
                        reasoning: { type: Type.STRING }
                      },
                      required: ["content", "status", "reasoning"]
                    },
                    when: {
                      type: Type.OBJECT,
                      properties: {
                        content: { type: Type.STRING },
                        status: { type: Type.STRING, enum: ["CLEAR", "BROAD", "MISSING"] },
                        reasoning: { type: Type.STRING }
                      },
                      required: ["content", "status", "reasoning"]
                    },
                    premise: {
                      type: Type.OBJECT,
                      properties: {
                        content: { type: Type.STRING },
                        status: { type: Type.STRING, enum: ["CLEAR", "BROAD", "MISSING"] },
                        reasoning: { type: Type.STRING }
                      },
                      required: ["content", "status", "reasoning"]
                    }
                  },
                  required: ["who", "action", "object", "measure", "when", "premise"]
                }
              },
              required: ["original_text", "highlighted_text", "debate_reason", "risk_profile", "assumptions_to_avoid", "verification_requirements", "elements"]
            },
            literal_translation: { type: Type.STRING }
          },
          required: ["statement_analysis", "literal_translation"]
        },
      },
    });

    if (!response.text) {
      throw new Error("Empty response from AI");
    }

    return JSON.parse(response.text) as FullAnalysisResponse;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

export const streamChat = async function* (history: { role: string; parts: { text: string }[] }[], newMessage: string) {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API Key missing");
  const ai = new GoogleGenAI({ apiKey });

  const chat = ai.chats.create({
    model: 'gemini-3-pro-preview', // Consistent model
    config: {
      systemInstruction: SYSTEM_PROMPT,
    },
    history: history
  });

  const result = await chat.sendMessageStream({ message: newMessage });
  for await (const chunk of result) {
    yield chunk.text;
  }
};

