// New function to fetch content via URL using Google Search Grounding
export const fetchUrlContent = async (url: string): Promise<string> => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API Key missing");

  const ai = new GoogleGenAI({ apiKey });

  // Use gemini-2.5-flash for fast retrieval with search tools
  // Improved prompt to handle URLs that might not be directly indexable
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: `I need to analyze the text content of the following article for a logic check.

    URL: ${url}

    Action:
    1. Use Google Search to find the text of this article. 
    2. If the direct URL doesn't yield a result, search for the article title or keywords embedded in the URL to find the content.
    3. Return a comprehensive summary or transcript of the claims, promises, and factual assertions made in the text.

    Constraint:
    - Do NOT provide a generic description of the website.
    - Provide the actual content/text of the article.`,
    config: {
      tools: [{ googleSearch: {} }],
      // Note: responseMimeType and responseSchema are NOT allowed with googleSearch
    },
  });

  if (!response.text) {
    // If no text, check if we have grounding metadata but no generated text (edge case)
    if (response.candidates?.[0]?.groundingMetadata) {
       return "Found related content but could not generate a transcript. Please try pasting the text directly.";
    }
    throw new Error("Google Search could not retrieve text for this URL. The content might be behind a paywall or not indexed.");
  }

  return response.text;
};

export const analyzeStatement = async (
  text: string, 
  fileData?: { mimeType: string; data: string }
): Promise<FullAnalysisResponse> => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API Key missing");

  const ai = new GoogleGenAI({ apiKey });

  // Construct contents based on whether file data is present
  let contents: any;
  if (fileData) {
    contents = {
      parts: [
        { inlineData: fileData },
        { text: text && text.trim() ? text : "Analyze the attached document for structural completeness and accountability." }
      ]
    };
  } else {
    contents = text;
  }

  // Internal helper to perform generation request
  const generateWithModel = async (model: string, budget: number) => {
    const response = await ai.models.generateContent({
      model: model,
      contents: contents,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        thinkingConfig: { thinkingBudget: budget },
        responseMimeType: "application/json",
        responseSchema: ANALYSIS_SCHEMA,
      },
    });
    if (!response.text) throw new Error(`Empty response from ${model}`);
    return JSON.parse(response.text) as FullAnalysisResponse;
  };

  try {
    // 1. Try Gemini 3 Pro (Deep Reasoning)
    return await generateWithModel('gemini-3-pro-preview', 32768);
  } catch (error: any) {
    // 2. Check for Resource Exhaustion (429) or Service Unavailable (503)
    const isQuotaError = 
      error.message?.includes('429') || 
      error.status === 429 || 
      error.message?.includes('Resource has been exhausted') ||
      error.message?.includes('quota');

    if (isQuotaError) {
      console.warn("Pro model exhausted. Falling back to Gemini 2.5 Flash.");
      try {
        // 3. Fallback to Gemini 2.5 Flash (Infinite/High Usage Model)
        // Using a moderate thinking budget (8k) for balance of quality/speed
        return await generateWithModel('gemini-2.5-flash', 8192);
      } catch (fallbackError) {
        // If Flash also fails, throw the original error or the new one
        console.error("Fallback model also failed:", fallbackError);
        throw error; 
      }
    }
    console.error("Gemini API Error:", error);
    throw error;
  }
};

export const streamChat = async function* (history: { role: string; parts: { text: string }[] }[], newMessage: string) {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API Key missing");
  const ai = new GoogleGenAI({ apiKey });

  let modelName = 'gemini-3-pro-preview';

  // Helper to create chat with current model
  const createChat = (m: string) => ai.chats.create({
    model: m,
    config: { systemInstruction: SYSTEM_PROMPT },
    history: history
  });

  let result;

  try {
    // Try Pro model first
    const chat = createChat(modelName);
    result = await chat.sendMessageStream({ message: newMessage });
  } catch (error: any) {
    const isQuotaError = 
      error.message?.includes('429') || 
      error.status === 429 || 
      error.message?.includes('Resource has been exhausted');

    if (isQuotaError) {
      // Fallback to Flash
      console.warn("Stream Pro exhausted. Switching to Flash.");
      modelName = 'gemini-2.5-flash';
      const fallbackChat = createChat(modelName);
      result = await fallbackChat.sendMessageStream({ message: newMessage });
    } else {
      throw error;
    }
  }

  for await (const chunk of result) {
    yield chunk.text;
  }
};

export enum ElementStatus {
  CLEAR = 'CLEAR',
  BROAD = 'BROAD',
  MISSING = 'MISSING',
}

export type ModelMode = 'reasoning' | 'quick';

export interface AnalysisElement {
  content: string;
  status: ElementStatus;
  reasoning: string;
}

export interface Assumption {
  assumption: string; // What the reader might incorrectly infer
  flaw: string;      // Why it is not structurally supported
  reality: string;   // What is actually written
}

export interface VerificationRequirement {
  requirement: string; // The specific fact needed (e.g. "A defined completion date")
  gap: string;        // The current deficiency (e.g. "Timeline is open-ended")
}

export interface WorstLine {
  text: string;      // The verbatim bad commitment
  flaw: string;      // Why it is a critical failure
}

export interface RiskProfile {
  tier_1_count: number;       // Number of clear commitments
  tier_2_count: number;       // Number of broad commitments
  tier_3_count: number;       // Number of missing/empty commitments
  unverifiable_claim_count: number; // Count of claims with no verification path
  worst_lines: WorstLine[];   // Top 1-3 worst offenders
}

export interface StatementAnalysis {
  original_text: string;
  highlighted_text: string; // Markdown bolding of commitments
  debate_reason: string; // One-liner on why it causes debate
  risk_profile: RiskProfile; // NEW: Document-level distribution stats
  assumptions_to_avoid: Assumption[]; // Safety checks
  verification_requirements: VerificationRequirement[]; // New: What is needed for accountability
  elements: {
    who: AnalysisElement;
    action: AnalysisElement;
    object: AnalysisElement;
    measure: AnalysisElement;
    when: AnalysisElement;
    premise: AnalysisElement;
  };
}

export interface FullAnalysisResponse {
  statement_analysis: StatementAnalysis;
  literal_translation: string;
}

export enum ClarityTier {
  TIER_1 = 'Tier 1 (Low Ambiguity)',
  TIER_2 = 'Tier 2 (Medium Ambiguity)',
  TIER_3 = 'Tier 3 (High Ambiguity)',
}

export interface CalculatedScore {
  rawPenaltyScore: number;
  finalAmbiguityScore: number;
  tier: ClarityTier;
  missingCount: number;
  criticalFailure: boolean; // True if Who and Action are both Missing
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

export interface AnalysisHistoryItem {
  id: string;
  timestamp: number;
  text: string;
  score: CalculatedScore;
  analysis: FullAnalysisResponse;
}

