// New function to fetch content via URL using Google Search Grounding
export const fetchUrlContent = async (url: string): Promise<string> => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API Key missing");

  const ai = new GoogleGenAI({ apiKey });

  // Use gemini-2.5-flash for fast retrieval with search tools
  // Improved prompt to handle URLs that might not be directly indexable
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash',
    contents: `I need to analyze the text content of the following article for a logic check.

    URL: ${url}

    Action:
    1. Use Google Search to find the text of this article. 
    2. If the direct URL doesn't yield a result, search for the article title or keywords embedded in the URL to find the content.
    3. Return a comprehensive summary or transcript of the claims, promises, and factual assertions made in the text.

    Constraint:
    - Do NOT provide a generic description of the website.
    - Provide the actual content/text of the article.`,
    config: {
      tools: [{ googleSearch: {} }],
      // Note: responseMimeType and responseSchema are NOT allowed with googleSearch
    },
  });

  if (!response.text) {
    // If no text, check if we have grounding metadata but no generated text (edge case)
    if (response.candidates?.[0]?.groundingMetadata) {
       return "Found related content but could not generate a transcript. Please try pasting the text directly.";
    }
    throw new Error("Google Search could not retrieve text for this URL. The content might be behind a paywall or not indexed.");
  }

  return response.text;
};

export const analyzeStatement = async (
  text: string, 
  fileData?: { mimeType: string; data: string },
  mode: ModelMode = 'reasoning'
): Promise<FullAnalysisResponse> => {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API Key missing");

  const ai = new GoogleGenAI({ apiKey });

  // Construct contents based on whether file data is present
  let contents: any;
  if (fileData) {
    contents = {
      parts: [
        { inlineData: fileData },
        { text: text && text.trim() ? text : "Analyze the attached document for structural completeness and accountability." }
      ]
    };
  } else {
    contents = text;
  }

  // Internal helper to perform generation request
  const generateWithModel = async (model: string, budget: number) => {
    const response = await ai.models.generateContent({
      model: model,
      contents: contents,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        thinkingConfig: { thinkingBudget: budget },
        responseMimeType: "application/json",
        responseSchema: ANALYSIS_SCHEMA,
      },
    });
    if (!response.text) throw new Error(`Empty response from ${model}`);
    return JSON.parse(response.text) as FullAnalysisResponse;
  };

  try {
    if (mode === 'quick') {
      // Direct Flash Usage (Lower Budget)
      return await generateWithModel('gemini-2.5-flash', 4096);
    } else {
      // Default: Reasoning Mode (Try Pro, Fallback to Flash)
      try {
        return await generateWithModel('gemini-3-pro-preview', 32768);
      } catch (error: any) {
         // Check for Resource Exhaustion (429) or Service Unavailable (503)
        const isQuotaError = 
          error.message?.includes('429') || 
          error.status === 429 || 
          error.message?.includes('Resource has been exhausted') ||
          error.message?.includes('quota');

        if (isQuotaError) {
          console.warn("Pro model exhausted. Auto-fallback to Gemini 2.5 Flash.");
          return await generateWithModel('gemini-2.5-flash', 8192);
        }
        throw error;
      }
    }
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

export const streamChat = async function* (history: { role: string; parts: { text: string }[] }[], newMessage: string) {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("API Key missing");
  const ai = new GoogleGenAI({ apiKey });

  // Chat defaults to Pro, falls back to Flash
  let modelName = 'gemini-3-pro-preview';

  // Helper to create chat with current model
  const createChat = (m: string) => ai.chats.create({
    model: m,
    config: { systemInstruction: SYSTEM_PROMPT },
    history: history
  });

  let result;

  try {
    // Try Pro model first
    const chat = createChat(modelName);
    result = await chat.sendMessageStream({ message: newMessage });
  } catch (error: any) {
    const isQuotaError = 
      error.message?.includes('429') || 
      error.status === 429 || 
      error.message?.includes('Resource has been exhausted');

    if (isQuotaError) {
      // Fallback to Flash
      console.warn("Stream Pro exhausted. Switching to Flash.");
      modelName = 'gemini-2.5-flash';
      const fallbackChat = createChat(modelName);
      result = await fallbackChat.sendMessageStream({ message: newMessage });
    } else {
      throw error;
    }
  }

  for await (const chunk of result) {
    yield chunk.text;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import Header from './components/Header';
import InputSection from './components/InputSection';
import ClarityCard from './components/ClarityCard';
