const App: React.FC = () => {
  const [analysis, setAnalysis] = useState<FullAnalysisResponse | null>(null);
  const [score, setScore] = useState<CalculatedScore | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [loadingMode, setLoadingMode] = useState<'default' | 'searching'>('default');
  const [error, setError] = useState<string | null>(null);
  const [history, setHistory] = useState<AnalysisHistoryItem[]>([]);
  const [isDarkMode, setIsDarkMode] = useState(false);

  // Model & Quota State
  const [modelMode, setModelMode] = useState<ModelMode>('reasoning');
  const [proQueriesLeft, setProQueriesLeft] = useState(50); // Simulating a daily session quota

  const resultRef = useRef<HTMLDivElement>(null);

  // Initialize Dark Mode based on system preference or local storage
  useEffect(() => {
    const savedTheme = localStorage.getItem('clarity_theme');
    if (savedTheme === 'dark' || (!savedTheme && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      setIsDarkMode(true);
      document.documentElement.classList.add('dark');
    } else {
      setIsDarkMode(false);
      document.documentElement.classList.remove('dark');
    }
  }, []);

  const toggleDarkMode = () => {
    if (isDarkMode) {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('clarity_theme', 'light');
      setIsDarkMode(false);
    } else {
      document.documentElement.classList.add('dark');
      localStorage.setItem('clarity_theme', 'dark');
      setIsDarkMode(true);
    }
  };

  // Load history from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem('clarity_ledger');
    if (saved) {
      try {
        setHistory(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse history");
      }
    }
  }, []);

  const saveToHistory = (newItem: AnalysisHistoryItem) => {
    const newHistory = [...history, newItem];
    // Keep last 10 items
    if (newHistory.length > 10) newHistory.shift(); 
    setHistory(newHistory);
    localStorage.setItem('clarity_ledger', JSON.stringify(newHistory));
  };

  const clearHistory = () => {
    setHistory([]);
    localStorage.removeItem('clarity_ledger');
  };

  const calculateScore = (analysisData: StatementAnalysis): CalculatedScore => {
    const els = analysisData.elements;
    let rawPenaltyScore = 0;
    let missingCount = 0;

    // Helper to calc element score
    const calcElement = (status: ElementStatus, weight: number) => {
      const penalty = STATUS_PENALTY_MULTIPLIER[status];
      if (status === ElementStatus.MISSING) missingCount++;
      return weight * penalty;
    };

    rawPenaltyScore += calcElement(els.who.status as ElementStatus, WEIGHTS.who);
    rawPenaltyScore += calcElement(els.action.status as ElementStatus, WEIGHTS.action);
    rawPenaltyScore += calcElement(els.object.status as ElementStatus, WEIGHTS.object);
    rawPenaltyScore += calcElement(els.measure.status as ElementStatus, WEIGHTS.measure);
    rawPenaltyScore += calcElement(els.when.status as ElementStatus, WEIGHTS.when);
    rawPenaltyScore += calcElement(els.premise.status as ElementStatus, WEIGHTS.premise);

    let finalAmbiguityScore = (rawPenaltyScore / MAX_SCORE) * 10;

    // Rule D: Hierarchy of Missing Elements
    // If WHO and ACTION are both MISSING, Score is 10.0
    const criticalFailure = els.who.status === ElementStatus.MISSING && els.action.status === ElementStatus.MISSING;
    if (criticalFailure) {
      finalAmbiguityScore = 10.0;
    }

    let tier = ClarityTier.TIER_1;
    if (finalAmbiguityScore > TIER_THRESHOLDS.TIER_2_LIMIT) {
      tier = ClarityTier.TIER_3;
    } else if (finalAmbiguityScore > TIER_THRESHOLDS.TIER_1_LIMIT) {
      tier = ClarityTier.TIER_2;
    }

    // Rule C: The Tier Floor Rule (3 Strikes)
    // If >= 3 elements are MISSING, auto Tier 3
    if (missingCount >= 3) {
      tier = ClarityTier.TIER_3;
    }

    return {
      rawPenaltyScore,
      finalAmbiguityScore,
      tier,
      missingCount,
      criticalFailure
    };
  };

  const handleModeChange = (newMode: ModelMode) => {
    if (newMode === 'reasoning' && proQueriesLeft <= 0) {
      alert("Pro Reasoning queries exhausted for this session. Switching to Quick mode.");
      setModelMode('quick');
      return;
    }
    setModelMode(newMode);
  };

  const handleAnalyze = async (text: string, fileData?: { mimeType: string, data: string }, url?: string) => {
    setIsLoading(true);
    setLoadingMode(url ? 'searching' : 'default');
    setError(null);
    setAnalysis(null);
    setScore(null);

    // Ensure we are in the right mode if queries are out
    let activeMode = modelMode;
    if (activeMode === 'reasoning' && proQueriesLeft <= 0) {
      activeMode = 'quick';
      setModelMode('quick');
    }

    // Scroll slightly to prepare for result
    if (window.innerWidth < 768) {
       window.scrollTo({ top: 100, behavior: 'smooth' });
    }

    try {
      let contentToAnalyze = text;

      // Step 1: Fetch Content if URL is provided
      if (url) {
        try {
          const retrievedText = await fetchUrlContent(url);
          contentToAnalyze = `[SOURCE: ${url}]\n\n${retrievedText}`;
          setLoadingMode('default'); // Switch back to normal skeleton for analysis phase
        } catch (fetchError: any) {
           // Directly throw the error message from the service
           throw new Error(fetchError.message || "Failed to retrieve URL content.");
        }
      }

      // Step 2: Analyze the content
      const result = await analyzeStatement(contentToAnalyze, fileData, activeMode);
      setAnalysis(result);
      const computedScore = calculateScore(result.statement_analysis);
      setScore(computedScore);

      // Update Quotas
      if (activeMode === 'reasoning') {
        setProQueriesLeft(prev => Math.max(0, prev - 1));
      }

      // Save to ledger
      let historyText = "";
      if (url) historyText = `[URL] ${url}`;
      else if (fileData) historyText = `[Doc] ${fileData.mimeType === 'application/pdf' ? 'PDF' : 'File'} ${text ? '+ ' + text : ''}`;
      else historyText = text;

      const historyItem: AnalysisHistoryItem = {
        id: Date.now().toString(),
        timestamp: Date.now(),
        text: historyText,
        score: computedScore,
        analysis: result
      };
      saveToHistory(historyItem);

      // Auto-scroll to result after short delay to allow render
      setTimeout(() => {
        resultRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
      }, 100);

    } catch (err: any) {
      console.error(err);
      setError(err.message || "Analysis failed. Please check your inputs or API key.");
    } finally {
      setIsLoading(false);
      setLoadingMode('default');
    }
  };

  const handleSelectHistory = (item: AnalysisHistoryItem) => {
    setAnalysis(item.analysis);
    setScore(item.score);
    setTimeout(() => {
        resultRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 100);
  };

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-slate-950 flex flex-col font-sans text-slate-900 dark:text-slate-100 selection:bg-slate-200 dark:selection:bg-slate-700 transition-colors duration-300">
      <Header 
        isDarkMode={isDarkMode} 
        toggleDarkMode={toggleDarkMode}
        currentMode={modelMode}
        setMode={handleModeChange}
        proQueriesLeft={proQueriesLeft}
      />

      <main className="flex-1 container mx-auto px-4 max-w-4xl py-8 md:py-12">

        <InputSection onAnalyze={handleAnalyze} isLoading={isLoading} />

        {error && (
           <div className="bg-rose-50 dark:bg-rose-900/20 border-l-4 border-rose-500 text-rose-800 dark:text-rose-200 p-4 mb-8 font-mono text-sm rounded-r" role="alert">
             <p className="font-bold mb-1">Error</p>
             <p>{error}</p>
           </div>
        )}

        <div ref={resultRef}>
          {isLoading && <AnalysisSkeleton mode={loadingMode} />}

          {analysis && score && (
            <ClarityCard analysis={analysis} score={score} />
          )}
        </div>

        <div className="mt-12 border-t border-slate-200 dark:border-slate-800 pt-8">
           <AccountabilityLedger 
            history={history} 
            onSelect={handleSelectHistory} 
            onClear={clearHistory} 
          />
        </div>

        {!analysis && !isLoading && !error && history.length === 0 && (
           <div className="text-center py-24 text-slate-400 dark:text-slate-500">
             <p className="font-mono text-xs uppercase tracking-widest mb-3 opacity-60">System Ready</p>
             <p className="font-sans text-sm md:text-base max-w-md mx-auto leading-relaxed">
               Paste a corporate statement, attach a PDF, or enter an article URL above to begin forensic structural analysis.
             </p>
           </div>
        )}
      </main>

      <footer className="bg-slate-50 dark:bg-slate-900 text-slate-400 dark:text-slate-500 py-8 border-t border-slate-200 dark:border-slate-800 transition-colors duration-300">
        <div className="container mx-auto px-4 max-w-4xl text-center">
          <p className="font-mono text-[10px] uppercase tracking-widest opacity-60">
            Powered by Gemini 3 Pro • Deep Reasoning Logic
          </p>
        </div>
      </footer>

      <ChatWidget />
    </div>
  );
};

export default App;

export enum ElementStatus {
  CLEAR = 'CLEAR',
  BROAD = 'BROAD',
  MISSING = 'MISSING',
}

export type ModelMode = 'reasoning' | 'quick';

export interface AnalysisElement {
  content: string;
  status: ElementStatus;
  reasoning: string;
}

export interface Assumption {
  assumption: string; // What the reader might incorrectly infer
  flaw: string;      // Why it is not structurally supported
  reality: string;   // What is actually written
}

export interface VerificationRequirement {
  requirement: string; // The specific fact needed (e.g. "A defined completion date")
  gap: string;        // The current deficiency (e.g. "Timeline is open-ended")
}

export interface WorstLine {
  text: string;      // The verbatim bad commitment
  flaw: string;      // Why it is a critical failure
}

export interface RhetoricDensity {
  binding_count: number;      // Count of binary, verifiable actions
  rhetorical_count: number;   // Count of expressive, ceremonial, or intent statements
  rhetorical_percentage: number; // 0-100
}

export interface RiskProfile {
  tier_1_count: number;       // Number of clear commitments
  tier_2_count: number;       // Number of broad commitments
  tier_3_count: number;       // Number of missing/empty commitments
  unverifiable_claim_count: number; // Count of claims with no verification path
  worst_lines: WorstLine[];   // Top 1-3 worst offenders
}

export interface StatementAnalysis {
  original_text: string;
  highlighted_text: string; // Markdown bolding of commitments
  debate_reason: string; // One-liner on why it causes debate
  risk_profile: RiskProfile; // Document-level distribution stats
  rhetoric_density: RhetoricDensity; // NEW: Fluff vs Substance ratio
  assumptions_to_avoid: Assumption[]; // Safety checks
  verification_requirements: VerificationRequirement[]; // What is needed for accountability
  elements: {
    who: AnalysisElement;
    action: AnalysisElement;
    object: AnalysisElement;
    measure: AnalysisElement;
    when: AnalysisElement;
    premise: AnalysisElement;
  };
}

export interface FullAnalysisResponse {
  statement_analysis: StatementAnalysis;
  literal_translation: string;
}

export enum ClarityTier {
  TIER_1 = 'Tier 1 (Low Ambiguity)',
  TIER_2 = 'Tier 2 (Medium Ambiguity)',
  TIER_3 = 'Tier 3 (High Ambiguity)',
}

export interface CalculatedScore {
  rawPenaltyScore: number;
  finalAmbiguityScore: number;
  tier: ClarityTier;
  missingCount: number;
  criticalFailure: boolean; // True if Who and Action are both Missing
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

export interface AnalysisHistoryItem {
  id: string;
  timestamp: number;
  text: string;
  score: CalculatedScore;
  analysis: FullAnalysisResponse;
}

import { ElementStatus } from './types';

export const SYSTEM_PROMPT = `
Role: You are The Clarity Engine, a rigorous logic analyzer. 
Input: A string of text or a document (political/corporate statement). 
Task: Deconstruct the text into 6 elements, assign states (CLEAR, BROAD, MISSING), identify unsafe assumptions, list missing verification facts, and calculate Rhetoric Density.
Constraint: Do not judge truth. Judge structural completeness. Tone: Clinical but accessible.

THE CLARITY DOCTRINE (STRICT RULES):

1. The Binary Action Rule (The "Did it happen?" Test):
   - CLEAR: Binary Event (Sign, Resign, Vote, Veto). Can be answered Yes/No AND directly executes the outcome.
   - BROAD: Process with Endpoint (Review, Draft, Negotiate) OR Passive Authorization (Approve, Authorize, Endorse, Clear, Greenlight, Sanction, Permit). These are binary but do not guarantee the underlying result or execution.
   - MISSING: Infinite Process / State of Being (Support, Fight, Believe, Prioritize, Ensure). No completion state.

2. The Premise Rule (Authoritative vs. Causal):
   - CLEAR: Points to External Reality (Data, Law, Specific Event).
   - BROAD: Points to Internal/Causal Logic ("To stimulate growth").
   - MISSING: Rhetorical/Circular ("Because it is right").

3. The Hierarchy of Missing Elements:
   - If WHO is Missing/Symbolic AND ACTION is Missing/Symbolic, it is a critical failure.

4. Rhetoric Density (Contextual Diagnostic):
   - Classify EVERY claim/sentence in the text into two buckets:
     A. BINDING: Binary, verifiable actions (e.g., "We will allocate $5M," "I sign this order").
     B. RHETORICAL: Expressive (emphasized, reaffirmed), Intent (seeks to, aims at), or Infinite Process (support, strengthen, remain committed).
   - Calculate the percentage of the total text that is Rhetorical.

DOCUMENT MODE INSTRUCTIONS:
If the input is longer than a single sentence (e.g. a speech, article, or PDF):
1. Scan the ENTIRE text for distinct commitments/claims.
2. Populate 'risk_profile' with the count of commitments falling into Tier 1 (Clear), Tier 2 (Broad), and Tier 3 (Missing/Vague).
3. Identify the 'unverifiable_claim_count' (claims that lack ANY measure or deadline).
4. Calculate 'rhetoric_density' statistics based on the Binding vs. Rhetorical classification.
5. Extract the top 1-3 'worst_lines' verbatim. These are the most dangerous sentences where high-stakes promises are made with zero structural accountability.
6. For the main 'elements' and 'literal_translation', select the SINGLE MOST REPRESENTATIVE or HEADLINE claim of the document to analyze in depth.

JSON Output Schema:
{
  "statement_analysis": {
    "original_text": "string",
    "highlighted_text": "string (The original text, but wrap ONLY the words that form specific structural commitments in markdown bold **like this**. Do not bold rhetorical fluff or broad promises.)",
    "debate_reason": "string (A single sentence explaining which missing or broad elements force the reader to guess, causing potential debate. E.g. 'Ambiguity arises because the timeline is open-ended and the success metric is undefined.')",
    "risk_profile": {
      "tier_1_count": "number (Count of CLEAR commitments)",
      "tier_2_count": "number (Count of BROAD commitments)",
      "tier_3_count": "number (Count of MISSING/VAGUE commitments)",
      "unverifiable_claim_count": "number",
      "worst_lines": [
        { "text": "string (Verbatim quote of the ambiguous line)", "flaw": "string (Why it fails)" }
      ]
    },
    "rhetoric_density": {
      "binding_count": "number (Count of sentences/claims containing binary, verifiable actions)",
      "rhetorical_count": "number (Count of sentences/claims containing expressive, ceremonial, or infinite-process language)",
      "rhetorical_percentage": "number (0 to 100, percentage of total statements that are rhetorical)"
    },
    "verification_requirements": [
      {
        "requirement": "string (A specific type of fact needed to make the statement verifyable. Do NOT suggest content. Example: 'A defined completion date' or 'A quantifiable success threshold'.)",
        "gap": "string (Why it is currently missing. Example: 'Timeline is described as soon' or 'Metric is qualitative'.)"
      }
    ],
    "assumptions_to_avoid": [
      {
        "assumption": "string (A specific, likely inference the reader might make that is NOT strictly supported by text)",
        "flaw": "string (Explain why this assumption is unsafe due to missing structure. Use neutral, non-judgmental language. Avoid words like 'fail' or 'error'.)",
        "reality": "string (Start with a simple, human-readable sentence stating exactly what is promised. You may include logical notation (like 'n > n-1') only AFTER the plain English explanation.)"
      }
    ],
    "elements": {
      "who": { "content": "string", "status": "CLEAR|BROAD|MISSING", "reasoning": "string" },
      "action": { "content": "string", "status": "CLEAR|BROAD|MISSING", "reasoning": "string" },
      "object": { "content": "string", "status": "CLEAR|BROAD|MISSING", "reasoning": "string" },
      "measure": { "content": "string", "status": "CLEAR|BROAD|MISSING", "reasoning": "string" },
      "when": { "content": "string", "status": "CLEAR|BROAD|MISSING", "reasoning": "string" },
      "premise": { "content": "string", "status": "CLEAR|BROAD|MISSING", "reasoning": "string" }
    }
  },
  "literal_translation": "string (The statement rewritten to include ONLY the clear commitments. If the statement contains multiple distinct atomic commitments, separate them with ' || ' delimiters. If nothing is clear, say 'No structural commitments found.')"
}
`;

