export enum ElementStatus {
  CLEAR = 'CLEAR',
  BROAD = 'BROAD',
  MISSING = 'MISSING',
}

export type ModelMode = 'reasoning' | 'quick';

export interface AnalysisElement {
  content: string;
  status: ElementStatus;
  reasoning: string;
}

export interface Assumption {
  assumption: string; // What the reader might incorrectly infer
  flaw: string;      // Why it is not structurally supported
  reality: string;   // What is actually written
}

export interface VerificationRequirement {
  requirement: string; // The specific fact needed (e.g. "A defined completion date")
  gap: string;        // The current deficiency (e.g. "Timeline is open-ended")
}

export interface WorstLine {
  text: string;      // The verbatim bad commitment
  flaw: string;      // Why it is a critical failure
}

export interface RhetoricDensity {
  binding_count: number;      // Count of binary, verifiable actions
  rhetorical_count: number;   // Count of expressive, ceremonial, or intent statements
  rhetorical_percentage: number; // 0-100
}

export interface RiskProfile {
  tier_1_count: number;       // Number of clear commitments
  tier_2_count: number;       // Number of broad commitments
  tier_3_count: number;       // Number of missing/empty commitments
  unverifiable_claim_count: number; // Count of claims with no verification path
  worst_lines: WorstLine[];   // Top 1-3 worst offenders
}

export interface StatementAnalysis {
  original_text: string;
  highlighted_text: string; // Markdown bolding of commitments
  debate_reason: string; // One-liner on why it causes debate
  risk_profile: RiskProfile; // Document-level distribution stats
  rhetoric_density: RhetoricDensity; // NEW: Fluff vs Substance ratio
  assumptions_to_avoid: Assumption[]; // Safety checks
  verification_requirements: VerificationRequirement[]; // What is needed for accountability
  elements: {
    who: AnalysisElement;
    action: AnalysisElement;
    object: AnalysisElement;
    measure: AnalysisElement;
    when: AnalysisElement;
    premise: AnalysisElement;
  };
}

export interface FullAnalysisResponse {
  statement_analysis: StatementAnalysis;
  literal_translation: string;
}

export enum KlaritexLevel {
  LEVEL_1 = 'Level 1 (Solid)',
