          <div className="w-2 h-2 rounded-full bg-slate-400 dark:bg-slate-500"></div>
          <span>Just Talk</span>
        </div>
        <div className="flex items-center gap-1">
          <div className="w-2 h-2 rounded-full bg-indigo-500 dark:bg-indigo-400"></div>
          <span>Locked In</span>
        </div>
      </div>
    </div>
  );
};

