          {showHighlight && (
             <div className="bg-white dark:bg-slate-900 p-8 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm animate-fade-in-up transition-colors duration-300">
                <div className="flex justify-between items-end mb-4">
                  <h4 className="text-xs font-bold font-mono uppercase text-slate-400">Signal Detection</h4>
                  <span className="text-[10px] font-mono text-emerald-600 dark:text-emerald-400 bg-emerald-50 dark:bg-emerald-900/20 px-2 py-1 rounded">Green = What's Locked In</span>
                </div>
                <p className="font-serif text-xl leading-loose text-slate-300 dark:text-slate-600 selection:bg-emerald-100 dark:selection:bg-emerald-900/50 selection:text-emerald-900 dark:selection:text-emerald-100">
                  {statement_analysis.highlighted_text ? renderHighlightedText(statement_analysis.highlighted_text) : renderHighlightedText("**" + statement_analysis.original_text + "**")}
