  KlaritexLevel,
  StatementAnalysis,
  AnalysisHistoryItem,
  ModelMode,
  AnalysisPipeline
} from './types';
import { WEIGHTS, STATUS_PENALTY_MULTIPLIER, MAX_SCORE, TIER_THRESHOLDS } from './constants';

const AnalysisSkeleton = ({ mode, pipeline }: { mode: 'default' | 'searching', pipeline: AnalysisPipeline }) => (
